import numpy as np
import prism.mr_adc_overlap as mr_adc_overlap
import prism.mr_adc_intermediates as mr_adc_intermediates

import prism.lib.logger as logger
import prism.lib.tools as tools

import prism.cvs_ee.transition_moments as q2_trans_mom
import prism.cvs_ee.sigma_vector as h1_h1_sigma

def compute_excitation_manifolds(mr_adc):

    # MR-ADC(0) and MR-ADC(1)
    mr_adc.h0.n_ca = mr_adc.ncvs * mr_adc.ncas
    mr_adc.h0.n_ce = mr_adc.ncvs * mr_adc.nextern

    ## Zeroth-order manifold
    mr_adc.h0.dim_ca = mr_adc.h0.n_ca
    mr_adc.h0.dim_ce = mr_adc.h0.n_ce
    mr_adc.h0.dim = mr_adc.h0.dim_ce + mr_adc.h0.dim_ca

    mr_adc.h0.s_ca = 0
    mr_adc.h0.f_ca = mr_adc.h0.s_ca + mr_adc.h0.n_ca
    mr_adc.h0.s_ce = mr_adc.h0.f_ca
    mr_adc.h0.f_ce = mr_adc.h0.s_ce + mr_adc.h0.n_ce

    mr_adc.h0.ca = slice(mr_adc.h0.s_ca, mr_adc.h0.f_ca)
    mr_adc.h0.ce = slice(mr_adc.h0.s_ce, mr_adc.h0.f_ce)

    mr_adc.log.extra("\nDimension of h0 excitation manifold:                       %d" % mr_adc.h0.dim)

    # Orthogonalized zeroth-order manifold
    mr_adc.S12.ca = mr_adc_overlap.compute_S12_p1(mr_adc)

    mr_adc.h_orth.n_ca_caaa = mr_adc.ncvs * mr_adc.S12.ca.shape[1]
    mr_adc.h_orth.n_ce_caea = mr_adc.h0.n_ce

    mr_adc.h_orth.dim_ca_caaa = mr_adc.h_orth.n_ca_caaa 
    mr_adc.h_orth.dim_ce_caea = mr_adc.h_orth.n_ce_caea  
    mr_adc.h_orth.dim = mr_adc.h_orth.dim_ce_caea + mr_adc.h_orth.dim_ca_caaa 

    mr_adc.h_orth.s_ca_caaa = 0
    mr_adc.h_orth.f_ca_caaa = mr_adc.h_orth.s_ca_caaa + mr_adc.h_orth.n_ca_caaa
    mr_adc.h_orth.s_ce_caea = mr_adc.h_orth.f_ca_caaa
    mr_adc.h_orth.f_ce_caea = mr_adc.h_orth.s_ce_caea + mr_adc.h_orth.n_ce_caea

    mr_adc.h_orth.ca_caaa = slice(mr_adc.h_orth.s_ca_caaa, mr_adc.h_orth.f_ca_caaa)
    mr_adc.h_orth.ce_caea = slice(mr_adc.h_orth.s_ce_caea, mr_adc.h_orth.f_ce_caea)

    # MR-ADC(2), MR-ADC(2)-SX, and MR-ADC(2)-X
    mr_adc.h1.dim = 0
    mr_adc.h_orth.dim = mr_adc.h0.dim

    if mr_adc.method in ("mr-adc(2)", "mr-adc(2)-sx", "mr-adc(2)-x"):
        # Compound Indices
        mr_adc.h1.n_aa = mr_adc.ncas * (mr_adc.ncas - 1) // 2

        ## Indices
        mr_adc.h1.aa_tril_ind = np.tril_indices(mr_adc.ncas, k = -1)

        ## First-order manifold
        # double-core excitations
        mr_adc.h1.n_ccaa = mr_adc.ncvs * mr_adc.ncvs * mr_adc.ncas * mr_adc.ncas
        mr_adc.h1.n_ccea = mr_adc.ncvs * mr_adc.ncvs * mr_adc.nextern * mr_adc.ncas
        mr_adc.h1.n_ccee = mr_adc.ncvs * mr_adc.ncvs * mr_adc.nextern * mr_adc.nextern

        # single-core excitations
        mr_adc.h1.n_caee = mr_adc.ncvs * mr_adc.ncas * mr_adc.nextern * mr_adc.nextern
        mr_adc.h1.n_caaa = mr_adc.ncvs * mr_adc.ncas * mr_adc.ncas * mr_adc.ncas
        mr_adc.h1.n_caaa_tril = mr_adc.ncvs * mr_adc.ncas * (mr_adc.ncas * (mr_adc.ncas - 1) // 2)
        mr_adc.h1.n_caea = mr_adc.ncvs * mr_adc.ncas * mr_adc.nextern * mr_adc.ncas

        mr_adc.h1.dim_ccaa = mr_adc.h1.n_ccaa
        mr_adc.h1.dim_ccee = mr_adc.h1.n_ccee
        mr_adc.h1.dim_ccea = mr_adc.h1.n_ccea
        mr_adc.h1.dim_caee = mr_adc.h1.n_caee

        mr_adc.h1.dim_caaa = mr_adc.h1.n_caaa + mr_adc.h1.n_caaa_tril
        mr_adc.h1.dim_caea = 3 * mr_adc.h1.n_caea

        if mr_adc.nval > 0:
            mr_adc.h1.n_cvaa = mr_adc.ncvs * mr_adc.nval * mr_adc.ncas * mr_adc.ncas
            mr_adc.h1.n_cvea = mr_adc.ncvs * mr_adc.nval * mr_adc.ncas * mr_adc.nextern
            mr_adc.h1.n_cvee = mr_adc.ncvs * mr_adc.nval * mr_adc.nextern * mr_adc.nextern 

            mr_adc.h1.dim_cvaa = mr_adc.h1.n_cvaa
            mr_adc.h1.dim_cvea = 2 * mr_adc.h1.n_cvea
            mr_adc.h1.dim_cvee = mr_adc.h1.n_cvee

        # Total dimension
        mr_adc.h1.dim = mr_adc.h1.dim_ccaa + mr_adc.h1.dim_ccea + mr_adc.h1.dim_ccee + mr_adc.h1.dim_caee + mr_adc.h1.dim_caaa + mr_adc.h1.dim_caea

        if mr_adc.nval > 0:
            mr_adc.h1.dim += mr_adc.h1.dim_cvaa + mr_adc.h1.dim_cvea + mr_adc.h1.dim_cvee

        ## Indices
        if mr_adc.nval == 0:
            blocks = ['ccaa', 'ccea', 'ccee', 'caee', 'caaa', 'caea']
        else:
            blocks = ['ccaa', 'cvaa', 'ccea', 'cvea', 'ccee', 'cvee', 'caee', 'caaa', 'caea']

        current_start = mr_adc.h0.dim
        for block in blocks:
            setattr(mr_adc.h1, f's_{block}', current_start)
            dim = getattr(mr_adc.h1, f'dim_{block}')
            end = current_start + dim
            setattr(mr_adc.h1, f'f_{block}', end)
            current_start = end

        ## Case Indices
        # CCAA (CVAA)
        mr_adc.h1.ccaa = slice(mr_adc.h1.s_ccaa, mr_adc.h1.f_ccaa)

        if mr_adc.nval > 0:
            mr_adc.h1.cvaa = slice(mr_adc.h1.s_cvaa, mr_adc.h1.f_cvaa)

        # CCEA (CVEA)
        mr_adc.h1.ccea = slice(mr_adc.h1.s_ccea, mr_adc.h1.f_ccea)
        if mr_adc.nval > 0:
            mr_adc.h1.s_cvea__abab = mr_adc.h1.s_cvea
            mr_adc.h1.f_cvea__abab = mr_adc.h1.s_cvea__abab + mr_adc.h1.n_cvea
            mr_adc.h1.s_cvea__baab = mr_adc.h1.f_cvea__abab
            mr_adc.h1.f_cvea__baab = mr_adc.h1.s_cvea__baab + mr_adc.h1.n_cvea

            mr_adc.h1.cvea__abab = slice(mr_adc.h1.s_cvea__abab, mr_adc.h1.f_cvea__abab)
            mr_adc.h1.cvea__baab = slice(mr_adc.h1.s_cvea__baab, mr_adc.h1.f_cvea__baab)

        # CCEE (CVEE)
        mr_adc.h1.ccee = slice(mr_adc.h1.s_ccee, mr_adc.h1.f_ccee)
        if mr_adc.nval > 0:
            mr_adc.h1.cvee = slice(mr_adc.h1.s_cvee, mr_adc.h1.f_cvee)

        # CAEE  
        mr_adc.h1.caee = slice(mr_adc.h1.s_caee, mr_adc.h1.f_caee)

        # CAAA
        mr_adc.h1.s_caaa__aaaa = mr_adc.h1.s_caaa
        mr_adc.h1.f_caaa__aaaa = mr_adc.h1.s_caaa__aaaa + mr_adc.h1.n_caaa_tril
        mr_adc.h1.s_caaa__abab = mr_adc.h1.f_caaa__aaaa
        mr_adc.h1.f_caaa__abab = mr_adc.h1.s_caaa__abab + mr_adc.h1.n_caaa

        mr_adc.h1.caaa__aaaa = slice(mr_adc.h1.s_caaa__aaaa, mr_adc.h1.f_caaa__aaaa)
        mr_adc.h1.caaa__abab = slice(mr_adc.h1.s_caaa__abab, mr_adc.h1.f_caaa__abab)

        # CAEA
        mr_adc.h1.s_caea__aaaa = mr_adc.h1.s_caea
        mr_adc.h1.f_caea__aaaa = mr_adc.h1.s_caea__aaaa + mr_adc.h1.n_caea
        mr_adc.h1.s_caea__abab = mr_adc.h1.f_caea__aaaa
        mr_adc.h1.f_caea__abab = mr_adc.h1.s_caea__abab + mr_adc.h1.n_caea
        mr_adc.h1.s_caea__baab = mr_adc.h1.f_caea__abab
        mr_adc.h1.f_caea__baab = mr_adc.h1.s_caea__baab + mr_adc.h1.n_caea

        mr_adc.h1.caea__aaaa = slice(mr_adc.h1.s_caea__aaaa, mr_adc.h1.f_caea__aaaa)
        mr_adc.h1.caea__abab = slice(mr_adc.h1.s_caea__abab, mr_adc.h1.f_caea__abab)
        mr_adc.h1.caea__baab = slice(mr_adc.h1.s_caea__baab, mr_adc.h1.f_caea__baab)

        mr_adc.log.extra("Dimension of h1 excitation manifold:                       %d" % mr_adc.h1.dim)

        # Orthogonalized zeroth- and first-order manifold
        if not hasattr(mr_adc.S12, "ccaa"):
            mr_adc.S12.ccaa = mr_adc_overlap.compute_S12_p2(mr_adc)
        if not hasattr(mr_adc.S12, "ccea"):
            mr_adc.S12.ccea = mr_adc_overlap.compute_S12_p1(mr_adc)
        if not hasattr(mr_adc.S12, "caee"):
            mr_adc.S12.caee = mr_adc_overlap.compute_S12_m1(mr_adc)

        mr_adc.S12.ca_caaa = mr_adc_overlap.compute_S12_p1p_projector(mr_adc)
        mr_adc.S12.ce_caea = mr_adc_overlap.compute_S12_0p_projector(mr_adc)

        # double-core excitations
        mr_adc.h_orth.n_ccaa = mr_adc.ncvs * mr_adc.ncvs * mr_adc.S12.ccaa.shape[1]
        mr_adc.h_orth.n_ccea = mr_adc.ncvs * mr_adc.ncvs * mr_adc.nextern * mr_adc.S12.ccea.shape[1]
        mr_adc.h_orth.n_ccee = mr_adc.h1.n_ccee

        if mr_adc.nval > 0:
           mr_adc.h_orth.n_cvaa = (mr_adc.ncvs * mr_adc.nval) * mr_adc.S12.ccaa.shape[1]
           mr_adc.h_orth.n_cvea = (mr_adc.ncvs * mr_adc.nval) * mr_adc.nextern * mr_adc.S12.ccea.shape[1]
           mr_adc.h_orth.n_cvee = mr_adc.h1.n_cvee 

        # single-core excitations
        mr_adc.h_orth.n_caee = mr_adc.ncvs * mr_adc.nextern * mr_adc.nextern * mr_adc.S12.caee.shape[1]

        mr_adc.h_orth.n_ca_caaa = mr_adc.ncvs * mr_adc.S12.ca_caaa.shape[1]
        mr_adc.h_orth.n_ce_caea = mr_adc.ncvs * mr_adc.nextern * mr_adc.S12.ce_caea.shape[1]

        # Total dimension
        mr_adc.h_orth.dim_ca_caaa = mr_adc.h_orth.n_ca_caaa 
        mr_adc.h_orth.dim_ce_caea = mr_adc.h_orth.n_ce_caea

        mr_adc.h_orth.dim_ccaa = mr_adc.h_orth.n_ccaa
        mr_adc.h_orth.dim_ccea = mr_adc.h_orth.n_ccea
        mr_adc.h_orth.dim_ccee = mr_adc.h1.dim_ccee
        mr_adc.h_orth.dim_caee = mr_adc.h_orth.n_caee

        mr_adc.h_orth.dim =  mr_adc.h_orth.dim_ca_caaa + mr_adc.h_orth.dim_ce_caea + mr_adc.h_orth.dim_ccaa + mr_adc.h_orth.dim_ccea + mr_adc.h_orth.dim_ccee + mr_adc.h_orth.dim_caee

        if mr_adc.nval > 0:
            mr_adc.h_orth.dim_cvaa = mr_adc.h_orth.n_cvaa
            mr_adc.h_orth.dim_cvea = 2 * mr_adc.h_orth.n_cvea
            mr_adc.h_orth.dim_cvee = mr_adc.h1.dim_cvee
            mr_adc.h_orth.dim += mr_adc.h_orth.dim_cvaa + mr_adc.h_orth.dim_cvea + mr_adc.h_orth.dim_cvee

        ## Indices
        if mr_adc.nval == 0:
            blocks = ['ca_caaa', 'ce_caea', 'ccaa', 'ccea', 'ccee', 'caee']
        else:
            blocks = ['ca_caaa', 'ce_caea', 'ccaa', 'cvaa', 'ccea', 'cvea', 'ccee', 'cvee', 'caee']

        current_start = 0
        for block in blocks:
            setattr(mr_adc.h_orth, f's_{block}', current_start)
            dim = getattr(mr_adc.h_orth, f'dim_{block}')
            end = current_start + dim
            setattr(mr_adc.h_orth, f'f_{block}', end)
            current_start = end

        ## Case Indices
        # CA_CAAA
        mr_adc.h_orth.ca_caaa = slice(mr_adc.h_orth.s_ca_caaa, mr_adc.h_orth.f_ca_caaa)

        # CE_CAEA
        mr_adc.h_orth.ce_caea = slice(mr_adc.h_orth.s_ce_caea, mr_adc.h_orth.f_ce_caea)

        # CCAA (CVAA)
        mr_adc.h_orth.ccaa = slice(mr_adc.h_orth.s_ccaa, mr_adc.h_orth.f_ccaa)
        if mr_adc.nval > 0:
            mr_adc.h_orth.cvaa = slice(mr_adc.h_orth.s_cvaa, mr_adc.h_orth.f_cvaa)

        # CCEA (CVEA)
        mr_adc.h_orth.ccea = slice(mr_adc.h_orth.s_ccea, mr_adc.h_orth.f_ccea)
        if mr_adc.nval > 0:
            mr_adc.h_orth.s_cvea__abab = mr_adc.h_orth.s_cvea
            mr_adc.h_orth.f_cvea__abab = mr_adc.h_orth.s_cvea__abab + mr_adc.h_orth.n_cvea
            mr_adc.h_orth.s_cvea__baab = mr_adc.h_orth.f_cvea__abab
            mr_adc.h_orth.f_cvea__baab = mr_adc.h_orth.s_cvea__baab + mr_adc.h_orth.n_cvea

            mr_adc.h_orth.cvea__abab = slice(mr_adc.h_orth.s_cvea__abab, mr_adc.h_orth.f_cvea__abab)
            mr_adc.h_orth.cvea__baab = slice(mr_adc.h_orth.s_cvea__baab, mr_adc.h_orth.f_cvea__baab)

        # CCEE (CVEE)
        mr_adc.h_orth.ccee = slice(mr_adc.h_orth.s_ccee, mr_adc.h_orth.f_ccee)
        if mr_adc.nval > 0:
            mr_adc.h_orth.cvee = slice(mr_adc.h_orth.s_cvee, mr_adc.h_orth.f_cvee)

        # CAEE
        mr_adc.h_orth.caee = slice(mr_adc.h_orth.s_caee, mr_adc.h_orth.f_caee)

    mr_adc.log.extra("Total dimension of the excitation manifold:                %d" % (mr_adc.h0.dim + mr_adc.h1.dim))
    mr_adc.log.extra("Dimension of the orthogonalized excitation manifold:       %d" % (mr_adc.h_orth.dim))

    if (mr_adc.h_orth.dim < mr_adc.nroots):
        mr_adc.nroots = mr_adc.h_orth.dim

    return mr_adc

##TODO: change printouts from extra to debug
def compute_M_00(mr_adc):

    cput0 = (logger.process_clock(), logger.perf_counter())
    mr_adc.log.extra("\nComputing M(h0-h0) block...")

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    # Dimensions
    ce = mr_adc.h0.ce
    ca = mr_adc.h0.ca

    n_ce = mr_adc.h0.n_ce
    n_ca = mr_adc.h0.n_ca

    # Variables from kernel
    ncvs    = mr_adc.ncvs
    nval    = mr_adc.nval
    ncas    = mr_adc.ncas
    nextern = mr_adc.nextern

    ## Molecular Orbitals Energies
    e_cvs    = mr_adc.mo_energy.x
    e_val    = mr_adc.mo_energy.v
    e_extern = mr_adc.mo_energy.e

    ## Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca

    # M(h0-h0) Block
    M_00 = np.zeros((mr_adc.h0.dim, mr_adc.h0.dim))

    ## Zeroth-order terms
    cput1 = (logger.process_clock(), logger.perf_counter())

    # CE - CE
    d_ai = e_extern[:, None] - e_cvs
    np.fill_diagonal(M_00[ce, ce], d_ai.T.ravel())

    temp = M_00[ce, ce]
    mr_adc.log.extra(f"CE-CE H0 | Asymmetry: {np.linalg.norm(temp-temp.T):>.5e} | Norm: {np.linalg.norm(temp):>10.6f}")
    del d_ai, temp

    # CA - CA
    # Define Koopmans intermediate
    K_ac = mr_adc_intermediates.compute_K_ac(mr_adc)

    temp  = einsum('IJ,XY->IXJY',  np.identity(ncvs), K_ac)
    temp -= einsum('J,IJ,XY->IXJY', e_cvs, np.identity(ncvs), np.identity(ncas), optimize = einsum_type)
    temp += 1/2 * einsum('J,IJ,XY->IXJY', e_cvs, np.identity(ncvs), rdm_ca, optimize = einsum_type)

    temp.shape = (n_ca, n_ca)
    M_00[ca, ca] += temp

    mr_adc.log.extra(f"CA-CA H0 | Asymmetry: {np.linalg.norm(temp-temp.T):>.5e} | Norm: {np.linalg.norm(temp):>10.6f}\n")
    del temp, K_ac

    mr_adc.log.timer_debug("computing M(h0-h0) H1", *cput1)

    ## First-order terms
    if mr_adc.method in ("mr-adc(1)", "mr-adc(2)", "mr-adc(2)-sx", "mr-adc(2)-x"): 
        cput1 = (logger.process_clock(), logger.perf_counter())

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa
        h_ae = mr_adc.h1eff.ae
            
        ## Two-electron integrals
        v_xxaa = mr_adc.v2e.xxaa
        v_xxae = mr_adc.v2e.xxae
        v_xaax = mr_adc.v2e.xaax
        v_xaex = mr_adc.v2e.xaex
        v_aaaa = mr_adc.v2e.aaaa
        v_aaae = mr_adc.v2e.aaae

        ## Amplitudes
        t1_ae = mr_adc.t1.ae
        t1_aaae = mr_adc.t1.aaae

        ## Reduced Density Matrices
        rdm_ccaa = mr_adc.rdm.ccaa

        # CE - CE
        temp = np.zeros((ncvs, nextern, ncvs, nextern))

        chunks = tools.calculate_chunks(mr_adc, nextern, [ncvs, ncvs, nextern], ntensors = 3)
        for i_chunk, (s_chunk, f_chunk) in enumerate(chunks):
            cput2 = (logger.process_clock(), logger.perf_counter())
            mr_adc.log.debug("v2e.xeex v2e.xxee [%i/%i], chunk [%i:%i]", i_chunk + 1, len(chunks), s_chunk, f_chunk)

            ## Two-electron integrals
            v_xeex = mr_adc.v2e.xeex[:, s_chunk:f_chunk, :, :]
            v_xxee = mr_adc.v2e.xxee[:, :, s_chunk:f_chunk, :]

            temp[:, s_chunk:f_chunk] += 2 * v_xeex.transpose(0, 1, 3, 2) - v_xxee.transpose(1, 2, 0, 3)

            mr_adc.log.timer_debug("computing v2e.xeex v2e.xxee", *cput2)
            del v_xeex, v_xxee

        temp.shape = (n_ce, n_ce)
        M_00[ce, ce] += temp

        mr_adc.log.extra(f"CE-CE H1 | Asymmetry: {np.linalg.norm(temp-temp.T):>.5e} | Norm: {np.linalg.norm(temp):>10.6f}")
        del temp

        # CA - CA
        temp =- einsum('IJYX->IXJY', v_xxaa, optimize = einsum_type).copy()
        temp += 2 * einsum('IXYJ->IXJY', v_xaax, optimize = einsum_type).copy()
        temp += 1/2 * einsum('IJYx,Xx->IXJY', v_xxaa, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('IJxX,Yx->IXJY', v_xxaa, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('IJxy,XxYy->IXJY', v_xxaa, rdm_ccaa, optimize = einsum_type)
        temp -= einsum('IXxJ,Yx->IXJY', v_xaax, rdm_ca, optimize = einsum_type)
        temp -= einsum('IxYJ,Xx->IXJY', v_xaax, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('IxyJ,XyxY->IXJY', v_xaax, rdm_ccaa, optimize = einsum_type)
        temp -= 1/2 * einsum('IJxy,xy,XY->IXJY', v_xxaa, rdm_ca, rdm_ca, optimize = einsum_type)
        temp += 1/4 * einsum('IxyJ,yx,XY->IXJY', v_xaax, rdm_ca, rdm_ca, optimize = einsum_type)

        temp.shape = (n_ca, n_ca)
        M_00[ca, ca] += temp

        mr_adc.log.extra(f"CA-CA H1 | Asymmetry: {np.linalg.norm(temp - temp.T):>.5e} | Norm: {np.linalg.norm(temp):>10.6f}")
        del temp

        # CE - CA
        temp =- einsum('IJXA->IAJX', v_xxae, optimize = einsum_type).copy()
        temp += 2 * einsum('JXAI->IAJX', v_xaex, optimize = einsum_type).copy()
        temp += einsum('XA,IJ->IAJX', h_ae, np.identity(ncvs), optimize = einsum_type)
        temp += 1/2 * einsum('IJxA,Xx->IAJX', v_xxae, rdm_ca, optimize = einsum_type)
        temp -= einsum('JxAI,Xx->IAJX', v_xaex, rdm_ca, optimize = einsum_type)
        temp += einsum('A,IJ,XA->IAJX', e_extern, np.identity(ncvs), t1_ae, optimize = einsum_type)
        temp -= einsum('Xx,IJ,xA->IAJX', h_aa, np.identity(ncvs), t1_ae, optimize = einsum_type)
        temp -= 1/2 * einsum('IJ,XxyA,xy->IAJX', np.identity(ncvs), v_aaae, rdm_ca, optimize = einsum_type)
        temp += einsum('IJ,xyXA,yx->IAJX', np.identity(ncvs), v_aaae, rdm_ca, optimize = einsum_type)
        temp -= 1/2 * einsum('A,IJ,XxyA,yx->IAJX', e_extern, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp += einsum('A,IJ,xXyA,yx->IAJX', e_extern, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('Xx,IJ,xyzA,zy->IAJX', h_aa, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp -= einsum('Xx,IJ,yxzA,zy->IAJX', h_aa, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('xy,IJ,XxzA,yz->IAJX', h_aa, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp -= 1/2 * einsum('xy,IJ,XzxA,yz->IAJX', h_aa, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp -= einsum('xy,IJ,xXzA,yz->IAJX', h_aa, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp += einsum('xy,IJ,zXxA,yz->IAJX', h_aa, np.identity(ncvs), t1_aaae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('IJ,XxyA,xzwu,ywzu->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp -= 1/2 * einsum('IJ,XxyA,yzwu,xwzu->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp -= einsum('IJ,xA,Xxyz,yz->IAJX', np.identity(ncvs), t1_ae, v_aaaa, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('IJ,xA,Xyzx,zy->IAJX', np.identity(ncvs), t1_ae, v_aaaa, rdm_ca, optimize = einsum_type)
        temp -= einsum('IJ,xXyA,xzwu,ywzu->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp += einsum('IJ,xXyA,yzwu,xwzu->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp += 1/2 * einsum('IJ,xyzA,Xwux,zwuy->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp += 1/2 * einsum('IJ,xyzA,Xwuy,zwxu->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp -= 1/2 * einsum('IJ,xyzA,Xwzu,yxwu->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp += 1/2 * einsum('IJ,xyzA,Xxwu,zuyw->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp += 1/2 * einsum('IJ,xyzA,Xxwy,zw->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ca, optimize = einsum_type)
        temp -= einsum('IJ,xyzA,Xywu,zuxw->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        temp -= einsum('IJ,xyzA,Xywx,zw->IAJX', np.identity(ncvs), t1_aaae, v_aaaa, rdm_ca, optimize = einsum_type)

        temp.shape = (n_ce, n_ca)
        M_00[ce, ca] += temp

        # Add temp matrix to bottom triangle
        M_00[ca, ce] += temp.T

        mr_adc.log.extra(f"CE-CA H1 |                        | Norm: {np.linalg.norm(temp):>10.6f}")
        del temp

        mr_adc.log.timer_debug("computing M(h0-h0) H1", *cput1)

    ## Second-order terms
    if mr_adc.method in ("mr-adc(2)", "mr-adc(2)-sx", "mr-adc(2)-x"):
        cput1 = (logger.process_clock(), logger.perf_counter())

        ## One-electron integrals
        h_xa = mr_adc.h1eff.xa
        h_va = mr_adc.h1eff.va
        h_xe = mr_adc.h1eff.xe
        h_ve = mr_adc.h1eff.ve

        ## Two-electron integrals
        v_xxxa = mr_adc.v2e.xxxa
        v_xxva = mr_adc.v2e.xxva
        v_vxxa = mr_adc.v2e.vxxa

        v_xxxe = mr_adc.v2e.xxxe
        v_xxve = mr_adc.v2e.xxve
        v_vxxe = mr_adc.v2e.vxxe

        v_xaxa = mr_adc.v2e.xaxa
        v_xava = mr_adc.v2e.xava
        v_vaxa = mr_adc.v2e.vaxa
        v_vava = mr_adc.v2e.vava

        v_xaxe = mr_adc.v2e.xaxe
        v_xave = mr_adc.v2e.xave
        v_vaxe = mr_adc.v2e.vaxe
        v_vave = mr_adc.v2e.vave

        v_xaae = mr_adc.v2e.xaae
        v_vaae = mr_adc.v2e.vaae

        v_xaea = mr_adc.v2e.xaea
        v_vaea = mr_adc.v2e.vaea

        v_xeaa = mr_adc.v2e.xeaa
        v_veaa = mr_adc.v2e.veaa

        v_xaaa = mr_adc.v2e.xaaa
        v_vaaa = mr_adc.v2e.vaaa

        ## Amplitudes
        t1_xa = mr_adc.t1.xa
        t1_va = mr_adc.t1.va

        t1_xe = mr_adc.t1.xe
        t1_ve = mr_adc.t1.ve

        t2_ae = mr_adc.t2.ae
        t2_aa = mr_adc.t2.aa

        t1_xxaa = mr_adc.t1.xxaa
        t1_xvaa = mr_adc.t1.xvaa
        t1_vxaa = mr_adc.t1.vxaa
        t1_vvaa = mr_adc.t1.vvaa

        t1_xxae = mr_adc.t1.xxae
        t1_xvae = mr_adc.t1.xvae
        t1_vxae = mr_adc.t1.vxae
        t1_vvae = mr_adc.t1.vvae

        t1_xaaa = mr_adc.t1.xaaa
        t1_vaaa = mr_adc.t1.vaaa

        t1_xaae = mr_adc.t1.xaae
        t1_vaae = mr_adc.t1.vaae

        t1_xaea = mr_adc.t1.xaea
        t1_vaea = mr_adc.t1.vaea

        # Reduced Density Matrices
        rdm_cccaaa = mr_adc.rdm.cccaaa
        rdm_ccccaaaa = mr_adc.rdm.ccccaaaa

        # CE - CE
        temp  = einsum('IixA,JxiB->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp -= 2 * einsum('IixA,ixJB->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp += einsum('IixA,JxiB->IAJB', t1_xvae, v_xave, optimize = einsum_type)
        temp -= 2 * einsum('IixA,ixJB->IAJB', t1_xvae, v_vaxe, optimize = einsum_type)
        temp += einsum('JixB,IxiA->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp -= 2 * einsum('JixB,ixIA->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp += einsum('JixB,IxiA->IAJB', t1_xvae, v_xave, optimize = einsum_type)
        temp -= 2 * einsum('JixB,ixIA->IAJB', t1_xvae, v_vaxe, optimize = einsum_type)
        temp += einsum('iA,JIiB->IAJB', t1_xe, v_xxxe, optimize = einsum_type)
        temp -= 2 * einsum('iA,iIJB->IAJB', t1_xe, v_xxxe, optimize = einsum_type)
        temp += einsum('iB,IJiA->IAJB', t1_xe, v_xxxe, optimize = einsum_type)
        temp -= 2 * einsum('iB,iJIA->IAJB', t1_xe, v_xxxe, optimize = einsum_type)
        temp -= 2 * einsum('iIxA,JxiB->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp += 4 * einsum('iIxA,ixJB->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp -= 2 * einsum('iJxB,IxiA->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp += 4 * einsum('iJxB,ixIA->IAJB', t1_xxae, v_xaxe, optimize = einsum_type)
        temp += einsum('iA,JIiB->IAJB', t1_ve, v_xxve, optimize = einsum_type)
        temp -= 2 * einsum('iA,iIJB->IAJB', t1_ve, v_vxxe, optimize = einsum_type)
        temp += einsum('iB,IJiA->IAJB', t1_ve, v_xxve, optimize = einsum_type)
        temp -= 2 * einsum('iB,iJIA->IAJB', t1_ve, v_vxxe, optimize = einsum_type)
        temp -= 2 * einsum('iIxA,JxiB->IAJB', t1_vxae, v_xave, optimize = einsum_type)
        temp += 4 * einsum('iIxA,ixJB->IAJB', t1_vxae, v_vaxe, optimize = einsum_type)
        temp -= 2 * einsum('iJxB,IxiA->IAJB', t1_vxae, v_xave, optimize = einsum_type)
        temp += 4 * einsum('iJxB,ixIA->IAJB', t1_vxae, v_vaxe, optimize = einsum_type)
        temp -= 2 * einsum('xA,IxBJ->IAJB', t1_ae, v_xaex, optimize = einsum_type)
        temp += einsum('xA,JIxB->IAJB', t1_ae, v_xxae, optimize = einsum_type)
        temp += einsum('xB,IJxA->IAJB', t1_ae, v_xxae, optimize = einsum_type)
        temp -= 2 * einsum('xB,JxAI->IAJB', t1_ae, v_xaex, optimize = einsum_type)
        temp += 1/2 * einsum('A,IixA,JixB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= einsum('A,IixA,iJxB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += 1/2 * einsum('A,IixA,JixB->IAJB', e_extern, t1_xvae, t1_xvae, optimize = einsum_type)
        temp -= einsum('A,IixA,iJxB->IAJB', e_extern, t1_xvae, t1_vxae, optimize = einsum_type)
        temp -= einsum('A,iIxA,JixB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += 2 * einsum('A,iIxA,iJxB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= einsum('A,iIxA,JixB->IAJB', e_extern, t1_vxae, t1_xvae, optimize = einsum_type)
        temp += 2 * einsum('A,iIxA,iJxB->IAJB', e_extern, t1_vxae, t1_vxae, optimize = einsum_type)
        temp += 1/2 * einsum('B,IixA,JixB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= einsum('B,IixA,iJxB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += 1/2 * einsum('B,IixA,JixB->IAJB', e_extern, t1_xvae, t1_xvae, optimize = einsum_type)
        temp -= einsum('B,IixA,iJxB->IAJB', e_extern, t1_xvae, t1_vxae, optimize = einsum_type)
        temp -= einsum('B,iIxA,JixB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += 2 * einsum('B,iIxA,iJxB->IAJB', e_extern, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= einsum('B,iIxA,JixB->IAJB', e_extern, t1_vxae, t1_xvae, optimize = einsum_type)
        temp += 2 * einsum('B,iIxA,iJxB->IAJB', e_extern, t1_vxae, t1_vxae, optimize = einsum_type)
        temp -= 1/2 * einsum('I,IixA,JixB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += einsum('I,IixA,iJxB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= 1/2 * einsum('I,IixA,JixB->IAJB', e_cvs, t1_xvae, t1_xvae, optimize = einsum_type)
        temp += einsum('I,IixA,iJxB->IAJB', e_cvs, t1_xvae, t1_vxae, optimize = einsum_type)
        temp += einsum('I,iIxA,JixB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= 2 * einsum('I,iIxA,iJxB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += einsum('I,iIxA,JixB->IAJB', e_cvs, t1_vxae, t1_xvae, optimize = einsum_type)
        temp -= 2 * einsum('I,iIxA,iJxB->IAJB', e_cvs, t1_vxae, t1_vxae, optimize = einsum_type)
        temp -= 1/2 * einsum('J,IixA,JixB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += einsum('J,IixA,iJxB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= 1/2 * einsum('J,IixA,JixB->IAJB', e_cvs, t1_xvae, t1_xvae, optimize = einsum_type)
        temp += einsum('J,IixA,iJxB->IAJB', e_cvs, t1_xvae, t1_vxae, optimize = einsum_type)
        temp += einsum('J,iIxA,JixB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= 2 * einsum('J,iIxA,iJxB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += einsum('J,iIxA,JixB->IAJB', e_cvs, t1_vxae, t1_xvae, optimize = einsum_type)
        temp -= 2 * einsum('J,iIxA,iJxB->IAJB', e_cvs, t1_vxae, t1_vxae, optimize = einsum_type)
        temp -= einsum('i,IixA,JixB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += 2 * einsum('i,IixA,iJxB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += 2 * einsum('i,JixB,iIxA->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= 4 * einsum('i,iIxA,iJxB->IAJB', e_cvs, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= einsum('i,IixA,JixB->IAJB', e_val, t1_xvae, t1_xvae, optimize = einsum_type)
        temp += 2 * einsum('i,IixA,iJxB->IAJB', e_val, t1_xvae, t1_vxae, optimize = einsum_type)
        temp += 2 * einsum('i,JixB,iIxA->IAJB', e_val, t1_xvae, t1_vxae, optimize = einsum_type)
        temp -= 4 * einsum('i,iIxA,iJxB->IAJB', e_val, t1_vxae, t1_vxae, optimize = einsum_type)
        temp += einsum('xy,IixA,JiyB->IAJB', h_aa, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= 2 * einsum('xy,IixA,iJyB->IAJB', h_aa, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += einsum('xy,IixA,JiyB->IAJB', h_aa, t1_xvae, t1_xvae, optimize = einsum_type)
        temp -= 2 * einsum('xy,IixA,iJyB->IAJB', h_aa, t1_xvae, t1_vxae, optimize = einsum_type)
        temp -= 2 * einsum('xy,iIxA,JiyB->IAJB', h_aa, t1_xxae, t1_xxae, optimize = einsum_type)
        temp += 4 * einsum('xy,iIxA,iJyB->IAJB', h_aa, t1_xxae, t1_xxae, optimize = einsum_type)
        temp -= 2 * einsum('xy,iIxA,JiyB->IAJB', h_aa, t1_vxae, t1_xvae, optimize = einsum_type)
        temp += 4 * einsum('xy,iIxA,iJyB->IAJB', h_aa, t1_vxae, t1_vxae, optimize = einsum_type)
        temp -= einsum('AB,Ia,Ja->IAJB', np.identity(nextern), h_xe, t1_xe, optimize = einsum_type)
        temp -= einsum('AB,Ix,Jx->IAJB', np.identity(nextern), h_xa, t1_xa, optimize = einsum_type)
        temp -= einsum('AB,Ja,Ia->IAJB', np.identity(nextern), h_xe, t1_xe, optimize = einsum_type)
        temp -= einsum('AB,Jx,Ix->IAJB', np.identity(nextern), h_xa, t1_xa, optimize = einsum_type)
        temp -= einsum('IJ,iA,iB->IAJB', np.identity(ncvs), h_xe, t1_xe, optimize = einsum_type)
        temp -= einsum('IJ,iB,iA->IAJB', np.identity(ncvs), h_xe, t1_xe, optimize = einsum_type)
        temp -= einsum('IJ,iA,iB->IAJB', np.identity(ncvs), h_ve, t1_ve, optimize = einsum_type)
        temp -= einsum('IJ,iB,iA->IAJB', np.identity(ncvs), h_ve, t1_ve, optimize = einsum_type)
        temp -= einsum('IJ,xA,xB->IAJB', np.identity(ncvs), h_ae, t1_ae, optimize = einsum_type)
        temp -= einsum('IJ,xB,xA->IAJB', np.identity(ncvs), h_ae, t1_ae, optimize = einsum_type)
        temp -= 2 * einsum('AB,Iixa,Jxia->IAJB', np.identity(nextern), t1_xxae, v_xaxe, optimize = einsum_type)
        temp += einsum('AB,Iixa,ixJa->IAJB', np.identity(nextern), t1_xxae, v_xaxe, optimize = einsum_type)
        temp -= 2 * einsum('AB,Iixy,Jxiy->IAJB', np.identity(nextern), t1_xxaa, v_xaxa, optimize = einsum_type)
        temp += einsum('AB,Iixy,Jyix->IAJB', np.identity(nextern), t1_xxaa, v_xaxa, optimize = einsum_type)
        temp -= 2 * einsum('AB,Iixa,Jxia->IAJB', np.identity(nextern), t1_xvae, v_xave, optimize = einsum_type)
        temp += einsum('AB,Iixa,ixJa->IAJB', np.identity(nextern), t1_xvae, v_vaxe, optimize = einsum_type)
        temp -= 2 * einsum('AB,Iixy,Jxiy->IAJB', np.identity(nextern), t1_xvaa, v_xava, optimize = einsum_type)
        temp += einsum('AB,Iixy,Jyix->IAJB', np.identity(nextern), t1_xvaa, v_xava, optimize = einsum_type)
        temp -= 2 * einsum('AB,Jixa,Ixia->IAJB', np.identity(nextern), t1_xxae, v_xaxe, optimize = einsum_type)
        temp += einsum('AB,Jixa,ixIa->IAJB', np.identity(nextern), t1_xxae, v_xaxe, optimize = einsum_type)
        temp -= 2 * einsum('AB,Jixy,Ixiy->IAJB', np.identity(nextern), t1_xxaa, v_xaxa, optimize = einsum_type)
        temp += einsum('AB,Jixy,Iyix->IAJB', np.identity(nextern), t1_xxaa, v_xaxa, optimize = einsum_type)
        temp -= 2 * einsum('AB,Jixa,Ixia->IAJB', np.identity(nextern), t1_xvae, v_xave, optimize = einsum_type)
        temp += einsum('AB,Jixa,ixIa->IAJB', np.identity(nextern), t1_xvae, v_vaxe, optimize = einsum_type)
        temp -= 2 * einsum('AB,Jixy,Ixiy->IAJB', np.identity(nextern), t1_xvaa, v_xava, optimize = einsum_type)
        temp += einsum('AB,Jixy,Iyix->IAJB', np.identity(nextern), t1_xvaa, v_xava, optimize = einsum_type)
        temp += einsum('AB,iIxa,Jxia->IAJB', np.identity(nextern), t1_xxae, v_xaxe, optimize = einsum_type)
        temp -= 2 * einsum('AB,iIxa,ixJa->IAJB', np.identity(nextern), t1_xxae, v_xaxe, optimize = einsum_type)
        temp += einsum('AB,iJxa,Ixia->IAJB', np.identity(nextern), t1_xxae, v_xaxe, optimize = einsum_type)
