        temp_t1_0p += 1/12 * einsum('XY,xyzw,Jxua,Ivas,zuvwsy->IXJY', np.identity(ncas), v_aaaa, t1_xaae, t1_xaea, rdm_cccaaa, optimize = einsum_type)
        temp_t1_0p -= 1/6 * einsum('XY,xyzw,Jxua,Ivas,zuvwys->IXJY', np.identity(ncas), v_aaaa, t1_xaae, t1_xaea, rdm_cccaaa, optimize = einsum_type)
        temp_t1_0p += 1/12 * einsum('XY,xyzw,Jxua,Ivas,zuvysw->IXJY', np.identity(ncas), v_aaaa, t1_xaae, t1_xaea, rdm_cccaaa, optimize = einsum_type)
        temp_t1_0p += 1/12 * einsum('XY,xyzw,Jxua,Ivas,zuvyws->IXJY', np.identity(ncas), v_aaaa, t1_xaae, t1_xaea, rdm_cccaaa, optimize = einsum_type)
        temp_t1_0p -= 1/4 * einsum('XY,xyzw,Jxua,Ivau,zvwy->IXJY', np.identity(ncas), v_aaaa, t1_xaae, t1_xaea, rdm_ccaa, optimize = einsum_type)
        temp_t1_0p -= 1/4 * einsum('XY,xyzw,Jxua,Ivsa,zuvwsy->IXJY', np.identity(ncas), v_aaaa, t1_xaae, t1_xaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_0p += 1/2 * einsum('XY,xyzw,Jxua,Ivua,zvwy->IXJY', np.identity(ncas), v_aaaa, t1_xaae, t1_xaae, rdm_ccaa, optimize = einsum_type)
        temp += temp_t1_0p
        mr_adc.log.extra(">Norm of [0']  contribution: %20.12f" % np.linalg.norm(temp_t1_0p))
        del (temp_t1_0p)

        temp_t1_m1 = np.zeros_like(temp)

        chunks = tools.calculate_chunks(mr_adc, nextern, [ncvs, ncas, nextern], ntensors = 3)
        for i_chunk, (s_chunk, f_chunk) in enumerate(chunks):
            cput2 = (logger.process_clock(), logger.perf_counter())
            mr_adc.log.debug("v2e.xeae [%i/%i], chunk [%i:%i]", i_chunk + 1, len(chunks), s_chunk, f_chunk)

            ## Two-electron integrals
            v_xeae_ab = mr_adc.v2e.xeae[:, s_chunk:f_chunk, :, :]
            v_xeae_ba = mr_adc.v2e.xeae[:, :, :, s_chunk:f_chunk]

            ## Amplitudes
            t1_xaee = mr_adc.t1.xaee[:, :, s_chunk:f_chunk, :]

            temp_chunk =- einsum('IYab,JaXb->IXJY', t1_xaee, v_xeae_ab, optimize = einsum_type)
            temp_chunk += 2 * einsum('IYab,JbXa->IXJY', t1_xaee, v_xeae_ba, optimize = einsum_type)
            temp_chunk -= einsum('JXab,IaYb->IXJY', t1_xaee, v_xeae_ab, optimize = einsum_type)
            temp_chunk += 2 * einsum('JXab,IbYa->IXJY', t1_xaee, v_xeae_ba, optimize = einsum_type)
            temp_chunk += 2 * einsum('IJ,iXab,iaYb->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ab, optimize = einsum_type)
            temp_chunk -= einsum('IJ,iXab,ibYa->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ba, optimize = einsum_type)
            temp_chunk += 2 * einsum('IJ,iYab,iaXb->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ab, optimize = einsum_type)
            temp_chunk -= einsum('IJ,iYab,ibXa->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ba, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IYab,Jaxb,Xx->IXJY', t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IYab,Jbxa,Xx->IXJY', t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Ixab,JaXb,Yx->IXJY', t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Ixab,Jayb,XxYy->IXJY', t1_xaee, v_xeae_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= einsum('Ixab,JbXa,Yx->IXJY', t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Ixab,Jbya,XxyY->IXJY', t1_xaee, v_xeae_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('JXab,Iaxb,Yx->IXJY', t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('JXab,Ibxa,Yx->IXJY', t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Jxab,IaYb,Xx->IXJY', t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Jxab,Iayb,XyYx->IXJY', t1_xaee, v_xeae_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= einsum('Jxab,IbYa,Xx->IXJY', t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Jxab,Ibya,XyxY->IXJY', t1_xaee, v_xeae_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= einsum('IJ,iYab,iaxb,Xx->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,iYab,ibxa,Xx->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,ixab,iaYb,Xx->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,ixab,ibYa,Xx->IXJY', np.identity(ncvs), t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('XY,Ixab,Jayb,xy->IXJY', np.identity(ncas), t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,Ixab,Jbya,xy->IXJY', np.identity(ncas), t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('XY,Jxab,Iayb,xy->IXJY', np.identity(ncas), t1_xaee, v_xeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,Jxab,Ibya,xy->IXJY', np.identity(ncas), t1_xaee, v_xeae_ba, rdm_ca, optimize = einsum_type)

            temp_t1_m1 += temp_chunk
            mr_adc.log.timer_debug("computing v2e.xeae", *cput2)
            del (v_xeae_ab, v_xeae_ba, t1_xaee)

        for i_chunk, (s_chunk, f_chunk) in enumerate(chunks):
            cput2 = (logger.process_clock(), logger.perf_counter())
            mr_adc.log.debug("t1.xaee [%i/%i], chunk [%i:%i]", i_chunk + 1, len(chunks), s_chunk, f_chunk)

            ## Molecular Orbitals Energies
            e_extern_a = mr_adc.mo_energy.e[s_chunk:f_chunk]

            ## Amplitudes
            t1_xaee_ab = mr_adc.t1.xaee[:, :, s_chunk:f_chunk, :]
            t1_xaee_ba = mr_adc.t1.xaee[:, :, :, s_chunk:f_chunk]

            temp_chunk  = 1/2 * einsum('I,IYab,JXab->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk -= einsum('I,IYab,JXba->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('J,IYab,JXab->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk -= einsum('J,IYab,JXba->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('a,JXab,IYab->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk += 2 * einsum('a,JXab,IYba->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk += 2 * einsum('a,JXba,IYab->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ab, optimize = einsum_type)
            temp_chunk -= einsum('a,JXba,IYba->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ba, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Xx,Jxab,IYab->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk -= einsum('Xx,Jxab,IYba->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Yx,Ixab,JXab->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk -= einsum('Yx,Ixab,JXba->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('I,IYab,Jxab,Xx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('I,IYab,Jxba,Xx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('I,Ixab,JXab,Yx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('I,Ixab,JXba,Yx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('I,Ixab,Jyab,XxYy->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('I,Ixab,Jyba,XxyY->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('J,IYab,Jxab,Xx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('J,IYab,Jxba,Xx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('J,Ixab,JXab,Yx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('J,Ixab,JXba,Yx->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('J,Ixab,Jyab,XxYy->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('J,Ixab,Jyba,XxyY->IXJY', e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,JXab,Ixab,Yx->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('a,JXab,Ixba,Yx->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('a,JXba,Ixab,Yx->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,JXba,Ixba,Yx->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,Jxab,IYab,Xx->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('a,Jxab,IYba,Xx->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,Jxab,Iyab,XyYx->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,Jxab,Iyba,XyxY->IXJY', e_extern_a, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= einsum('a,Jxba,IYab,Xx->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,Jxba,IYba,Xx->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,Jxba,Iyab,XyxY->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('a,Jxba,Iyba,XyYx->IXJY', e_extern_a, t1_xaee_ba, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Xx,Jxab,Iyab,Yy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Xx,Jxab,Iyba,Yy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Yx,Ixab,Jyab,Xy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Yx,Ixab,Jyba,Xy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xy,Ixab,JXab,Yy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('xy,Ixab,JXba,Yy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xy,Ixab,Jzab,XyYz->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xy,Ixab,Jzba,XyzY->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xy,Jxab,IYab,Xy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('xy,Jxab,IYba,Xy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xy,Jxab,Izab,XzYy->IXJY', h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xy,Jxab,Izba,XzyY->IXJY', h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 2 * einsum('IJ,a,iXab,iYab->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,iXab,iYba->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,iXba,iYab->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ba, t1_xaee_ab, optimize = einsum_type)
            temp_chunk += 2 * einsum('IJ,a,iXba,iYba->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ba, t1_xaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,i,iXab,iYab->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,iXab,iYba->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,i,iYab,iXab->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,iYab,iXba->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,Xx,ixab,iYab->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Xx,ixab,iYba->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,Yx,ixab,iXab->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yx,ixab,iXba->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ba, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XYxy,Ixab,Jzab,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XYxy,Ixab,Jzba,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XYxy,Jyab,Izab,xz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XYxy,Jyab,Izba,xz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XxyY,Iyab,Jzab,xz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XxyY,Iyab,Jzba,xz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XxyY,Jxab,Izab,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XxyY,Jxab,Izba,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Xxyz,Iyab,Jwab,Ywxz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Xxyz,Iyab,Jwba,Ywzx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Xxyz,Jxab,IYab,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('Xxyz,Jxab,IYba,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Xxyz,Jxab,Iwab,Yywz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Xxyz,Jxab,Iwba,Yywz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Xxyz,Jzab,IYab,yx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Xxyz,Jzab,IYba,yx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Xxyz,Jzab,Iwab,Yyxw->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Xxyz,Jzab,Iwba,Yywx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Yxyz,Ixab,JXab,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('Yxyz,Ixab,JXba,yz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Yxyz,Ixab,Jwab,Xywz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Yxyz,Ixab,Jwba,Xywz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Yxyz,Izab,JXab,yx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('Yxyz,Izab,JXba,yx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Yxyz,Izab,Jwab,Xyxw->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Yxyz,Izab,Jwba,Xywx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Yxyz,Jyab,Iwab,Xwxz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('Yxyz,Jyab,Iwba,Xwzx->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xyzw,Ixab,JXab,Yzyw->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('xyzw,Ixab,JXba,Yzyw->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xyzw,Ixab,Juab,XywYuz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xyzw,Ixab,Juba,XywuYz->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xyzw,Jxab,IYab,Xzyw->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('xyzw,Jxab,IYba,Xzyw->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xyzw,Jxab,Iuab,XzuYwy->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('xyzw,Jxab,Iuba,XzuywY->IXJY', v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,ixab,iYab,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,a,ixab,iYba,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,a,ixba,iYab,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ba, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,ixba,iYba,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_xaee_ba, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,iYab,ixab,Xx->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,i,iYab,ixba,Xx->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,ixab,iYab,Xx->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,i,ixab,iYba,Xx->IXJY', np.identity(ncvs), e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,I,Ixab,Jyab,xy->IXJY', np.identity(ncas), e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XY,I,Ixab,Jyba,xy->IXJY', np.identity(ncas), e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,J,Ixab,Jyab,xy->IXJY', np.identity(ncas), e_cvs, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XY,J,Ixab,Jyba,xy->IXJY', np.identity(ncas), e_cvs, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('XY,a,Jxab,Iyab,xy->IXJY', np.identity(ncas), e_extern_a, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,a,Jxab,Iyba,xy->IXJY', np.identity(ncas), e_extern_a, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,a,Jxba,Iyab,xy->IXJY', np.identity(ncas), e_extern_a, t1_xaee_ba, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('XY,a,Jxba,Iyba,xy->IXJY', np.identity(ncas), e_extern_a, t1_xaee_ba, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yx,ixab,iyab,Xy->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,Yx,ixab,iyba,Xy->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,xy,ixab,iYab,Xy->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,xy,ixab,iYba,Xy->IXJY', np.identity(ncvs), h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,xy,Ixab,Jzab,yz->IXJY', np.identity(ncas), h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XY,xy,Ixab,Jzba,yz->IXJY', np.identity(ncas), h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,xy,Jxab,Izab,yz->IXJY', np.identity(ncas), h_aa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XY,xy,Jxab,Izba,yz->IXJY', np.identity(ncas), h_aa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,XYxy,ixab,izab,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,XYxy,ixab,izba,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,XYxy,iyab,izab,xz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,XYxy,iyab,izba,xz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,XxyY,ixab,izab,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,XxyY,ixab,izba,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,XxyY,iyab,izab,xz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,XxyY,iyab,izba,xz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,Xxyz,ixab,iYab,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Xxyz,ixab,iYba,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Xxyz,izab,iYab,yx->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,Xxyz,izab,iYba,yx->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,Yxyz,ixab,iXab,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yxyz,ixab,iXba,yz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yxyz,ixab,iwab,Xywz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,Yxyz,ixab,iwba,Xywz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yxyz,iyab,iwab,Xwxz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,Yxyz,iyab,iwba,Xwxz->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yxyz,izab,iXab,yx->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,Yxyz,izab,iXba,yx->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yxyz,izab,iwab,Xyxw->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,Yxyz,izab,iwba,Xyxw->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,xyzw,ixab,iYab,Xzyw->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,xyzw,ixab,iYba,Xzyw->IXJY', np.identity(ncvs), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,xyzw,Ixab,Juab,zuwy->IXJY', np.identity(ncas), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XY,xyzw,Ixab,Juba,zuwy->IXJY', np.identity(ncas), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('XY,xyzw,Jxab,Iuab,zuwy->IXJY', np.identity(ncas), v_aaaa, t1_xaee_ab, t1_xaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('XY,xyzw,Jxab,Iuba,zuwy->IXJY', np.identity(ncas), v_aaaa, t1_xaee_ab, t1_xaee_ba, rdm_ccaa, optimize = einsum_type)

            temp_t1_m1 += temp_chunk
            mr_adc.log.timer_debug("computing t1.xaee", *cput2)
            del (e_extern_a, t1_xaee_ab, t1_xaee_ba)

        chunks = tools.calculate_chunks(mr_adc, nextern, [nval, ncas, nextern], ntensors = 3)
        for i_chunk, (s_chunk, f_chunk) in enumerate(chunks):
            cput2 = (logger.process_clock(), logger.perf_counter())
            mr_adc.log.debug("v2e.veae [%i/%i], chunk [%i:%i]", i_chunk + 1, len(chunks), s_chunk, f_chunk)

            ## Two-electron integrals
            v_veae_ab = mr_adc.v2e.veae[:, s_chunk:f_chunk, :, :]
            v_veae_ba = mr_adc.v2e.veae[:, :, :, s_chunk:f_chunk]

            ## Amplitudes
            t1_vaee = mr_adc.t1.vaee[:, :, s_chunk:f_chunk, :]

            temp_chunk  = 2 * einsum('IJ,iXab,iaYb->IXJY', np.identity(ncvs), t1_vaee, v_veae_ab, optimize = einsum_type)
            temp_chunk -= einsum('IJ,iXab,ibYa->IXJY', np.identity(ncvs), t1_vaee, v_veae_ba, optimize = einsum_type)
            temp_chunk += 2 * einsum('IJ,iYab,iaXb->IXJY', np.identity(ncvs), t1_vaee, v_veae_ab, optimize = einsum_type)
            temp_chunk -= einsum('IJ,iYab,ibXa->IXJY', np.identity(ncvs), t1_vaee, v_veae_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,iYab,iaxb,Xx->IXJY', np.identity(ncvs), t1_vaee, v_veae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,iYab,ibxa,Xx->IXJY', np.identity(ncvs), t1_vaee, v_veae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,ixab,iaYb,Xx->IXJY', np.identity(ncvs), t1_vaee, v_veae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,ixab,ibYa,Xx->IXJY', np.identity(ncvs), t1_vaee, v_veae_ba, rdm_ca, optimize = einsum_type)

            temp_t1_m1 += temp_chunk
            mr_adc.log.timer_debug("computing v2e.veae", *cput2)
            del (v_veae_ab, v_veae_ba, t1_vaee)

        for i_chunk, (s_chunk, f_chunk) in enumerate(chunks):
            cput2 = (logger.process_clock(), logger.perf_counter())
            mr_adc.log.debug("t1.vaee [%i/%i], chunk [%i:%i]", i_chunk + 1, len(chunks), s_chunk, f_chunk)

            ## Molecular Orbitals Energies
            e_extern_a = mr_adc.mo_energy.e[s_chunk:f_chunk]

            ## Amplitudes
            t1_vaee_ab = mr_adc.t1.vaee[:, :, s_chunk:f_chunk, :]
            t1_vaee_ba = mr_adc.t1.vaee[:, :, :, s_chunk:f_chunk]

            temp_chunk  = 2 * einsum('IJ,a,iXab,iYab->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ab, t1_vaee_ab, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,iXab,iYba->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ab, t1_vaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,iXba,iYab->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ba, t1_vaee_ab, optimize = einsum_type)
            temp_chunk += 2 * einsum('IJ,a,iXba,iYba->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ba, t1_vaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,i,iXab,iYab->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,iXab,iYba->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,i,iYab,iXab->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,iYab,iXba->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,Xx,ixab,iYab->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Xx,ixab,iYba->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,Yx,ixab,iXab->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ab, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yx,ixab,iXba->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ba, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,ixab,iYab,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,a,ixab,iYba,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,a,ixba,iYab,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ba, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,a,ixba,iYba,Xx->IXJY', np.identity(ncvs), e_extern_a, t1_vaee_ba, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,iYab,ixab,Xx->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,i,iYab,ixba,Xx->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,i,ixab,iYab,Xx->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,i,ixab,iYba,Xx->IXJY', np.identity(ncvs), e_val, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,Yx,ixab,iyab,Xy->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,Yx,ixab,iyba,Xy->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,xy,ixab,iYab,Xy->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,xy,ixab,iYba,Xy->IXJY', np.identity(ncvs), h_aa, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,XYxy,ixab,izab,yz->IXJY', np.identity(ncvs), v_aaaa, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,XYxy,ixab,izba,yz->IXJY', np.identity(ncvs), v_aaaa, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= einsum('IJ,XYxy,iyab,izab,xz->IXJY', np.identity(ncvs), v_aaaa, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,XYxy,iyab,izba,xz->IXJY', np.identity(ncvs), v_aaaa, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/2 * einsum('IJ,XxyY,ixab,izab,yz->IXJY', np.identity(ncvs), v_aaaa, t1_vaee_ab, t1_vaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/4 * einsum('IJ,XxyY,ixab,izba,yz->IXJY', np.identity(ncvs), v_aaaa, t1_vaee_ab, t1_vaee_ba, rdm_ca, optimize = einsum_type)
