        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,xuva,sYva,Xzsywu->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,xuva,stYa,Xywustzv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/24 * einsum('IJ,xyzw,xuva,stYa,Xywusvzt->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/12 * einsum('IJ,xyzw,xuva,stYa,Xywusztv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/24 * einsum('IJ,xyzw,xuva,stYa,Xywuszvt->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,xuva,stYa,Xywutszv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,xuva,stYa,Xywutvzs->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/12 * einsum('IJ,xyzw,xuva,stYa,Xywutzsv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/12 * einsum('IJ,xyzw,xuva,stYa,Xywutzvs->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/48 * einsum('IJ,xyzw,xuva,stYa,Xywuvstz->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 3/16 * einsum('IJ,xyzw,xuva,stYa,Xywuvszt->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/48 * einsum('IJ,xyzw,xuva,stYa,Xywuvtsz->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/16 * einsum('IJ,xyzw,xuva,stYa,Xywuvtzs->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/48 * einsum('IJ,xyzw,xuva,stYa,Xywuvzst->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 5/48 * einsum('IJ,xyzw,xuva,stYa,Xywuvzts->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/16 * einsum('IJ,xyzw,xuva,stYa,Xywuzstv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/16 * einsum('IJ,xyzw,xuva,stYa,Xywuzsvt->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/16 * einsum('IJ,xyzw,xuva,stYa,Xywuztsv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/16 * einsum('IJ,xyzw,xuva,stYa,Xywuztvs->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/16 * einsum('IJ,xyzw,xuva,stYa,Xywuzvst->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/16 * einsum('IJ,xyzw,xuva,stYa,Xywuzvts->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccccaaaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,xzXa,uvYa,ywuv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,xzYa,ua,Xuyw->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_ae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,xzYa,uvXa,ywuv->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,xzYa,uvsa,Xvuyws->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,xzua,Yvua,Xvyw->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p -= 1/2 * einsum('IJ,xyzw,zxua,XvYa,ywvu->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,zxua,Ya,Xuyw->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_ae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p -= 1/2 * einsum('IJ,xyzw,zxua,YvXa,ywvu->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,zxua,Yvsa,Xuvswy->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,zxua,vXYa,ywvu->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,zxua,vYXa,ywvu->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,zxua,vYsa,Xuvswy->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,zxua,vYsa,Xuvsyw->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,zxua,vYsa,Xuvwsy->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,zxua,vYsa,Xuvwys->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p -= 1/12 * einsum('IJ,xyzw,zxua,vYsa,Xuvysw->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p += 1/6 * einsum('IJ,xyzw,zxua,vYsa,Xuvyws->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,zxua,vYua,Xvyw->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_ccaa, optimize = einsum_type)
        temp_t1_m1p += 1/4 * einsum('IJ,xyzw,zxua,vsYa,Xywvsu->IXJY', np.identity(ncvs), v_aaaa, t1_aaae, t1_aaae, rdm_cccaaa, optimize = einsum_type)

        temp += temp_t1_m1p
        mr_adc.log.extra(">Norm of [-1'] contribution: %20.12f" % np.linalg.norm(temp_t1_m1p))
        del (temp_t1_m1p) 

        temp_t1_m2 = np.zeros_like(temp)
        chunks = tools.calculate_chunks(mr_adc, nextern, [ncas, ncas, nextern], ntensors = 3)
        for i_chunk, (s_chunk, f_chunk) in enumerate(chunks):
            cput2 = (logger.process_clock(), logger.perf_counter())
            mr_adc.log.debug("v2e.aeae [%i/%i], chunk [%i:%i]", i_chunk + 1, len(chunks), s_chunk, f_chunk)

            ## Two-electron integrals
            v_aeae_ab = mr_adc.v2e.aeae[:, s_chunk:f_chunk, :, :]
            v_aeae_ba = mr_adc.v2e.aeae[:, :, :, s_chunk:f_chunk]

            ## Amplitudes
            t1_aaee = mr_adc.t1.aaee[:, :, s_chunk:f_chunk, :]

            temp_chunk  = einsum('IJ,Xxab,Yayb,xy->IXJY', np.identity(ncvs), t1_aaee, v_aeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,Xxab,Ybya,xy->IXJY', np.identity(ncvs), t1_aaee, v_aeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += einsum('IJ,Yxab,Xayb,xy->IXJY', np.identity(ncvs), t1_aaee, v_aeae_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,Yxab,Xbya,xy->IXJY', np.identity(ncvs), t1_aaee, v_aeae_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,Yxab,yazb,Xxyz->IXJY', np.identity(ncvs), t1_aaee, v_aeae_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,xyab,Yazb,Xzxy->IXJY', np.identity(ncvs), t1_aaee, v_aeae_ab, rdm_ccaa, optimize = einsum_type)

            temp_t1_m2 += temp_chunk
            mr_adc.log.timer_debug("computing v2e.aeae", *cput2)
        del(t1_aaee, v_aeae_ab, v_aeae_ba)

        for i_chunk, (s_chunk, f_chunk) in enumerate(chunks):
            cput2 = (logger.process_clock(), logger.perf_counter())
            mr_adc.log.debug("t1.aaee [%i/%i], chunk [%i:%i]", i_chunk + 1, len(chunks), s_chunk, f_chunk)

            ## Molecular Orbitals Energies
            e_extern_a = mr_adc.mo_energy.e[s_chunk:f_chunk]

            ## Amplitudes
            t1_aaee_ab = mr_adc.t1.aaee[:, :, s_chunk:f_chunk, :]
            t1_aaee_ba = mr_adc.t1.aaee[:, :, :, s_chunk:f_chunk]

            temp_chunk  = einsum('a,IJ,Xxab,Yyab,xy->IXJY', e_extern_a, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('a,IJ,Xxab,Yyba,xy->IXJY', e_extern_a, np.identity(ncvs), t1_aaee_ab, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('a,IJ,Xxba,Yyab,xy->IXJY', e_extern_a, np.identity(ncvs), t1_aaee_ba, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += einsum('a,IJ,Xxba,Yyba,xy->IXJY', e_extern_a, np.identity(ncvs), t1_aaee_ba, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('a,IJ,xyab,Yzab,Xzxy->IXJY', e_extern_a, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('a,IJ,xyab,Yzba,Xzyx->IXJY', e_extern_a, np.identity(ncvs), t1_aaee_ab, t1_aaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('Xx,IJ,xyab,Yzab,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('Xx,IJ,xyab,Yzba,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('Yx,IJ,xyab,Xzab,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('Yx,IJ,xyab,Xzba,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('Yx,IJ,xyab,zwab,Xyzw->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('xy,IJ,Xxab,Yzab,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('xy,IJ,Xxab,Yzba,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('xy,IJ,Yxab,Xzab,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('xy,IJ,Yxab,Xzba,yz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('xy,IJ,Yxab,zwab,Xyzw->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('xy,IJ,xzab,Ywab,Xwyz->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('xy,IJ,xzab,Ywba,Xwzy->IXJY', h_aa, np.identity(ncvs), t1_aaee_ab, t1_aaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,XYxy,xzab,wuab,yzwu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,XYxy,yzab,wuab,xzwu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,XxyY,xzab,wuab,yzwu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,XxyY,yzab,wuab,xzwu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Xxyz,Yyab,wuab,xzwu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,Xxyz,xwab,Yuab,ywzu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Xxyz,xwab,Yuba,ywzu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,Xxyz,xzab,Ywab,yw->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Xxyz,xzab,Ywba,yw->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Xxyz,zwab,Yuab,ywxu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Xxyz,zwab,Yuba,ywux->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Yxyz,Xyab,wuab,xzwu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,Yxyz,xwab,Xuab,ywzu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Yxyz,xwab,Xuba,ywzu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Yxyz,xwab,uvab,Xywuzv->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/2 * einsum('IJ,Yxyz,xzab,Xwab,yw->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Yxyz,xzab,Xwba,yw->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ba, rdm_ca, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Yxyz,xzab,wuab,Xywu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,ywab,uvab,Xuvwxz->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,ywab,uvab,Xuvwzx->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,ywab,uvab,Xuvxwz->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk += 5/24 * einsum('IJ,Yxyz,ywab,uvab,Xuvxzw->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,ywab,uvab,Xuvzwx->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,ywab,uvab,Xuvzxw->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Yxyz,zwab,Xuab,ywxu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_ccaa, optimize = einsum_type)
            temp_chunk += 1/4 * einsum('IJ,Yxyz,zwab,Xuba,ywux->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ba, rdm_ccaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,zwab,uvab,Xywuvx->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,zwab,uvab,Xywuxv->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,zwab,uvab,Xywvux->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk -= 1/24 * einsum('IJ,Yxyz,zwab,uvab,Xywvxu->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
            temp_chunk += 5/24 * einsum('IJ,Yxyz,zwab,uvab,Xywxuv->IXJY', np.identity(ncvs), v_aaaa, t1_aaee_ab, t1_aaee_ab, rdm_cccaaa, optimize = einsum_type)
