        temp -= 2 * einsum('JiXx,IxiA->IAJX', t1_xvaa, v_xave, optimize = einsum_type)
        temp += 4 * einsum('JiXx,ixIA->IAJX', t1_xvaa, v_vaxe, optimize = einsum_type)
