    # CE <- CCAA
    def compute_sigma_vector__H1__h0_h1__CE_CCAA(mr_adc, X, sigma): 

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Two-electron integrals
        v_xaea = mr_adc.v2e.xaea

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa
       
        sigma_KC =- einsum('Kixy,ixCy->KC', X, v_xaea, optimize = einsum_type)
        sigma_KC += 2 * einsum('Kixy,iyCx->KC', X, v_xaea, optimize = einsum_type)
        sigma_KC += 1/2 * einsum('Kixy,ixCz,yz->KC', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma_KC -= einsum('Kixy,iyCz,xz->KC', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma_KC += 1/2 * einsum('Kixy,izCw,xywz->KC', X, v_xaea, rdm_ccaa, optimize = einsum_type)
        sigma_KC -= einsum('Kixy,izCx,yz->KC', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma_KC += 1/2 * einsum('Kixy,izCy,xz->KC', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma[ce] += np.ascontiguousarray(sigma_KC).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h0-h1 CE-CCAA", *cput1)

    # CA <- CVAA
