    # CE <- CCEA
    def compute_sigma_vector__H1__h0_h1__CE_CCEA(mr_adc, X, sigma): 

        cput1 = (logger.process_clock(), logger.perf_counter())
 
        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Two-electron integrals
        #v_xeea = mr_adc.v2e.xeea
        #v_xaee = mr_adc.v2e.xaee
        v_xxxa = mr_adc.v2e.xxxa

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        #sigma_KC =- einsum('Kiax,iaCx->KC', X, v_xeea, optimize = einsum_type)
        #sigma_KC += 2 * einsum('Kiax,ixCa->KC', X, v_xaee, optimize = einsum_type)
        #sigma_KC += 2 * einsum('iKax,iaCx->KC', X, v_xeea, optimize = einsum_type)
        #sigma_KC -= einsum('iKax,ixCa->KC', X, v_xaee, optimize = einsum_type)
        sigma_KC =- 2 * einsum('ijCx,iKjx->KC', X, v_xxxa, optimize = einsum_type)
        sigma_KC += einsum('ijCx,jKix->KC', X, v_xxxa, optimize = einsum_type)
        #sigma_KC += 1/2 * einsum('Kiax,iaCy,xy->KC', X, v_xeea, rdm_ca, optimize = einsum_type)
        #sigma_KC -= einsum('Kiax,iyCa,xy->KC', X, v_xaee, rdm_ca, optimize = einsum_type)
        #sigma_KC -= einsum('iKax,iaCy,xy->KC', X, v_xeea, rdm_ca, optimize = einsum_type)
        #sigma_KC += 1/2 * einsum('iKax,iyCa,xy->KC', X, v_xaee, rdm_ca, optimize = einsum_type)
        sigma_KC += einsum('ijCx,iKjy,xy->KC', X, v_xxxa, rdm_ca, optimize = einsum_type)
        sigma_KC -= 1/2 * einsum('ijCx,jKiy,xy->KC', X, v_xxxa, rdm_ca, optimize = einsum_type)
        sigma[ce] += np.ascontiguousarray(sigma_KC).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h0-h1 CE-CCEA", *cput1)

    def compute_sigma_vector__H1__h0_h1__CE_CCEA__V_XAEE(mr_adc, X, v_xaee):

        cput1 = (logger.process_clock(), logger.perf_counter())
 
        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KC  = 2 * einsum('Kiax,ixCa->KC', X, v_xaee, optimize = einsum_type)
        sigma_KC -= einsum('iKax,ixCa->KC', X, v_xaee, optimize = einsum_type)
        sigma_KC -= einsum('Kiax,iyCa,xy->KC', X, v_xaee, rdm_ca, optimize = einsum_type)
        sigma_KC += 1/2 * einsum('iKax,iyCa,xy->KC', X, v_xaee, rdm_ca, optimize = einsum_type)
 
        mr_adc.log.timer_debug("contracting v2e.xaee", *cput1)
        return sigma_KC

    def compute_sigma_vector__H1__h0_h1__CE_CCEA__V_XEEA(mr_adc, X, v_xeea):

        cput1 = (logger.process_clock(), logger.perf_counter())
 
        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KC =- einsum('Kiax,iaCx->KC', X, v_xeea, optimize = einsum_type)
        sigma_KC += 2 * einsum('iKax,iaCx->KC', X, v_xeea, optimize = einsum_type)
        sigma_KC += 1/2 * einsum('Kiax,iaCy,xy->KC', X, v_xeea, rdm_ca, optimize = einsum_type)
        sigma_KC -= einsum('iKax,iaCy,xy->KC', X, v_xeea, rdm_ca, optimize = einsum_type)

        mr_adc.log.timer_debug("contracting v2e.xeea", *cput1)
        return sigma_KC

    # CA <- CVEA
    def compute_sigma_vector__H1__h0_h1__CA_CVEA(mr_adc, X_abab, X_baab, sigma): 

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_val = mr_adc.mo_energy.v
        e_extern = mr_adc.mo_energy.e

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_veaa = mr_adc.v2e.veaa
        v_vaae = mr_adc.v2e.vaae
        v_xxve = mr_adc.v2e.xxve 
        v_vaae = mr_adc.v2e.vaae 
        v_vxxe = mr_adc.v2e.vxxe 
        v_aaaa = mr_adc.v2e.aaaa
 
        ## Amplitudes
        t1_vaea = mr_adc.t1.vaea
        t1_vaae = mr_adc.t1.vaae
 
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa

        sigma_KW =- einsum('Kiax,iaWx->KW', X_abab, v_veaa, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,ixWa->KW', X_abab, v_vaae, optimize = einsum_type)
        sigma_KW += einsum('ijaW,iKja->KW', X_abab, v_xxve, optimize = einsum_type)
        sigma_KW -= 2 * einsum('ijaW,jKia->KW', X_abab, v_vxxe, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,iaWx->KW', X_baab, v_veaa, optimize = einsum_type)
        sigma_KW += einsum('Kiax,ixWa->KW', X_baab, v_vaae, optimize = einsum_type)
        sigma_KW += 2 * einsum('ijaW,iKja->KW', X_baab, v_xxve, optimize = einsum_type)
        sigma_KW -= einsum('ijaW,jKia->KW', X_baab, v_vxxe, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,a,iWax->KW', X_abab, e_extern, t1_vaea, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,a,iWxa->KW', X_abab, e_extern, t1_vaae, optimize = einsum_type)
        sigma_KW += einsum('Kiax,i,iWax->KW', X_abab, e_val, t1_vaea, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,i,iWxa->KW', X_abab, e_val, t1_vaae, optimize = einsum_type)
        sigma_KW += einsum('Kiax,Wy,iyax->KW', X_abab, h_aa, t1_vaea, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,Wy,iyxa->KW', X_abab, h_aa, t1_vaae, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,xy,iWay->KW', X_abab, h_aa, t1_vaea, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,xy,iWya->KW', X_abab, h_aa, t1_vaae, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iaWy,xy->KW', X_abab, v_veaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyWa,xy->KW', X_abab, v_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('ijax,iKja,Wx->KW', X_abab, v_xxve, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('ijax,jKia,Wx->KW', X_abab, v_vxxe, rdm_ca, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,a,iWax->KW', X_baab, e_extern, t1_vaea, optimize = einsum_type)
        sigma_KW += einsum('Kiax,a,iWxa->KW', X_baab, e_extern, t1_vaae, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,i,iWax->KW', X_baab, e_val, t1_vaea, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,i,iWxa->KW', X_baab, e_val, t1_vaae, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,Wy,iyax->KW', X_baab, h_aa, t1_vaea, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,Wy,iyxa->KW', X_baab, h_aa, t1_vaae, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,xy,iWay->KW', X_baab, h_aa, t1_vaea, optimize = einsum_type)
        sigma_KW += einsum('Kiax,xy,iWya->KW', X_baab, h_aa, t1_vaae, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iaWy,xy->KW', X_baab, v_veaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyWa,xy->KW', X_baab, v_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('ijax,iKja,Wx->KW', X_baab, v_xxve, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('ijax,jKia,Wx->KW', X_baab, v_vxxe, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,a,iWay,xy->KW', X_abab, e_extern, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,a,iWya,xy->KW', X_abab, e_extern, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,i,iWay,xy->KW', X_abab, e_val, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,i,iWya,xy->KW', X_abab, e_val, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,Wy,iyaz,xz->KW', X_abab, h_aa, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,Wy,iyza,xz->KW', X_abab, h_aa, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,yz,iWay,xz->KW', X_abab, h_aa, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,yz,iWya,xz->KW', X_abab, h_aa, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iWay,xyzw,zw->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iWay,xzwy,wz->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iWay,yzwu,xwzu->KW', X_abab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,iWya,xyzw,zw->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iWya,xzwy,wz->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iWya,yzwu,xwzu->KW', X_abab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyax,Wyzw,zw->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyax,Wzwy,wz->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyaz,Wwuy,xuwz->KW', X_abab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyaz,Wwzu,xywu->KW', X_abab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyaz,Wwzx,yw->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyaz,Wxwy,zw->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyaz,Wxzw,yw->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyaz,Wywu,xwzu->KW', X_abab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyaz,Wywx,zw->KW', X_abab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,iyxa,Wyzw,zw->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyxa,Wzwy,wz->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyza,Wwuy,xuzw->KW', X_abab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyza,Wwzu,xyuw->KW', X_abab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyza,Wwzx,yw->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyza,Wxwy,zw->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyza,Wxzw,yw->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyza,Wywu,xwzu->KW', X_abab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyza,Wywx,zw->KW', X_abab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,a,iWay,xy->KW', X_baab, e_extern, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,a,iWya,xy->KW', X_baab, e_extern, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,i,iWay,xy->KW', X_baab, e_val, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,i,iWya,xy->KW', X_baab, e_val, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,Wy,iyaz,xz->KW', X_baab, h_aa, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,Wy,iyza,xz->KW', X_baab, h_aa, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,yz,iWay,xz->KW', X_baab, h_aa, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,yz,iWya,xz->KW', X_baab, h_aa, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,iWay,xyzw,zw->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iWay,xzwy,wz->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iWay,yzwu,xwzu->KW', X_baab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iWya,xyzw,zw->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iWya,xzwy,wz->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iWya,yzwu,xwzu->KW', X_baab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,iyax,Wyzw,zw->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyax,Wzwy,wz->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyaz,Wwuy,xuwz->KW', X_baab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyaz,Wwzu,xywu->KW', X_baab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyaz,Wwzx,yw->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += 2 * einsum('Kiax,iyaz,Wxwy,zw->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= 2 * einsum('Kiax,iyaz,Wxzw,yw->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyaz,Wywu,xwzu->KW', X_baab, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyaz,Wywx,zw->KW', X_baab, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyxa,Wyzw,zw->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyxa,Wzwy,wz->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyza,Wwuy,xuwz->KW', X_baab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyza,Wwzu,xywu->KW', X_baab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW -= 1/2 * einsum('Kiax,iyza,Wwzx,yw->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW -= einsum('Kiax,iyza,Wxwy,zw->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += einsum('Kiax,iyza,Wxzw,yw->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyza,Wywu,xwzu->KW', X_baab, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KW += 1/2 * einsum('Kiax,iyza,Wywx,zw->KW', X_baab, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma[ca] += np.ascontiguousarray(sigma_KW).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h0-h1 CA-CVEA", *cput1)

    # CE <- CVEA 
    def compute_sigma_vector__H1__h0_h1__CE_CVEA(mr_adc, X_abab, X_baab, sigma): 

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Two-electron integrals
        #v_veea = mr_adc.v2e.veea
        #v_vaee = mr_adc.v2e.vaee
        v_xxva = mr_adc.v2e.xxva
        v_vxxa = mr_adc.v2e.vxxa
         
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        #sigma_KC =- einsum('Kiax,iaCx->KC', X_abab, v_veea, optimize = einsum_type)
        #sigma_KC += 2 * einsum('Kiax,ixCa->KC', X_abab, v_vaee, optimize = einsum_type)
        sigma_KC =- 2 * einsum('ijCx,iKjx->KC', X_abab, v_xxva, optimize = einsum_type)
        sigma_KC += einsum('ijCx,jKix->KC', X_abab, v_vxxa, optimize = einsum_type)
        #sigma_KC -= 2 * einsum('Kiax,iaCx->KC', X_baab, v_veea, optimize = einsum_type)
        #sigma_KC += einsum('Kiax,ixCa->KC', X_baab, v_vaee, optimize = einsum_type)
        sigma_KC -= einsum('ijCx,iKjx->KC', X_baab, v_xxva, optimize = einsum_type)
        sigma_KC += 2 * einsum('ijCx,jKix->KC', X_baab, v_vxxa, optimize = einsum_type)
        #sigma_KC += 1/2 * einsum('Kiax,iaCy,xy->KC', X_abab, v_veea, rdm_ca, optimize = einsum_type)
        #sigma_KC -= einsum('Kiax,iyCa,xy->KC', X_abab, v_vaee, rdm_ca, optimize = einsum_type)
        sigma_KC += einsum('ijCx,iKjy,xy->KC', X_abab, v_xxva, rdm_ca, optimize = einsum_type)
        sigma_KC -= 1/2 * einsum('ijCx,jKiy,xy->KC', X_abab, v_vxxa, rdm_ca, optimize = einsum_type)
        #sigma_KC += einsum('Kiax,iaCy,xy->KC', X_baab, v_veea, rdm_ca, optimize = einsum_type)
        #sigma_KC -= 1/2 * einsum('Kiax,iyCa,xy->KC', X_baab, v_vaee, rdm_ca, optimize = einsum_type)
        sigma_KC += 1/2 * einsum('ijCx,iKjy,xy->KC', X_baab, v_xxva, rdm_ca, optimize = einsum_type)
        sigma_KC -= einsum('ijCx,jKiy,xy->KC', X_baab, v_vxxa, rdm_ca, optimize = einsum_type)
        sigma[ce] += np.ascontiguousarray(sigma_KC).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h0-h1 CE-CVEA", *cput1)

    def compute_sigma_vector__H1__h0_h1__CE_CVEA__V_VAEE(mr_adc, X_abab, X_baab, v_vaee):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type
        
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KC  = 2 * einsum('Kiax,ixCa->KC', X_abab, v_vaee, optimize = einsum_type)
        sigma_KC += einsum('Kiax,ixCa->KC', X_baab, v_vaee, optimize = einsum_type)
        sigma_KC -= einsum('Kiax,iyCa,xy->KC', X_abab, v_vaee, rdm_ca, optimize = einsum_type)
        sigma_KC -= 1/2 * einsum('Kiax,iyCa,xy->KC', X_baab, v_vaee, rdm_ca, optimize = einsum_type)

        mr_adc.log.timer_debug("contracting v2e.vaee", *cput1)

        return sigma_KC

    def compute_sigma_vector__H1__h0_h1__CE_CVEA__V_VEEA(mr_adc, X_abab, X_baab, v_veea):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type
        
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KC =- einsum('Kiax,iaCx->KC', X_abab, v_veea, optimize = einsum_type)
        sigma_KC -= 2 * einsum('Kiax,iaCx->KC', X_baab, v_veea, optimize = einsum_type)
        sigma_KC += 1/2 * einsum('Kiax,iaCy,xy->KC', X_abab, v_veea, rdm_ca, optimize = einsum_type)
        sigma_KC += einsum('Kiax,iaCy,xy->KC', X_baab, v_veea, rdm_ca, optimize = einsum_type)

        mr_adc.log.timer_debug("contracting v2e.veea", *cput1)

        return sigma_KC

    # CA <- CCEE
    def compute_sigma_vector__H1__h0_h1__CA_CCEE__V_XEAE(mr_adc, X, v_xeae): 

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        sigma_KW =- einsum('Kiab,iaWb->KW', X, v_xeae, optimize = einsum_type)
