        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa
        rdm_cccaaa = mr_adc.rdm.cccaaa

        sigma_KC  = 1/2 * einsum('Kxyz,yC,xz->KC', X_aaaa, h_ae, rdm_ca, optimize = einsum_type)
