        sigma_KC += 1/3 * einsum('Kxyz,wxuC,yzuw->KC', X_abab, v_aaae, rdm_ccaa, optimize = einsum_type)
        sigma_KC += 1/6 * einsum('Kxyz,wxuC,yzwu->KC', X_abab, v_aaae, rdm_ccaa, optimize = einsum_type)
        sigma_KC -= 1/6 * einsum('Kxyz,ywuC,xuwz->KC', X_abab, v_aaae, rdm_ccaa, optimize = einsum_type)
        sigma_KC -= 1/3 * einsum('Kxyz,ywuC,xuzw->KC', X_abab, v_aaae, rdm_ccaa, optimize = einsum_type)
