        sigma_KC -= 1/2 * einsum('ixyz,KiyC,xz->KC', X_abab, v_xxae, rdm_ca, optimize = einsum_type)
        sigma_KC -= 1/3 * einsum('ixyz,iwCK,xwyz->KC', X_abab, v_xaex, rdm_ccaa, optimize = einsum_type)
        sigma_KC -= 2/3 * einsum('ixyz,iwCK,xwzy->KC', X_abab, v_xaex, rdm_ccaa, optimize = einsum_type)
