    ## h1 <- h0 coupling contributions
    # CCAA <- CA
    def compute_sigma_vector__H1__h1_h0__CCAA_CA(mr_adc, X, sigma):
 
        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_cvs = mr_adc.mo_energy.x
        
        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa
        v_xaaa = mr_adc.v2e.xaaa
        v_xxxa = mr_adc.v2e.xxxa
        
        ## Amplitudes
        t1_xa = mr_adc.t1.xa
        t1_xaaa = mr_adc.t1.xaaa
 
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa
        rdm_cccaaa = mr_adc.rdm.cccaaa

        sigma_KLWU  = einsum('Kx,LUxW->KLWU', X, v_xaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Lx,KWxU->KLWU', X, v_xaaa, optimize = einsum_type)
        sigma_KLWU -= einsum('iU,LiKW->KLWU', X, v_xxxa, optimize = einsum_type)
        sigma_KLWU -= einsum('iW,KiLU->KLWU', X, v_xxxa, optimize = einsum_type)
        sigma_KLWU -= einsum('Kx,L,LxUW->KLWU', X, e_cvs, t1_xaaa, optimize = einsum_type)
        sigma_KLWU -= einsum('Lx,K,KxWU->KLWU', X, e_cvs, t1_xaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Uy,LxyW->KLWU', X, h_aa, t1_xaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Wy,LxUy->KLWU', X, h_aa, t1_xaaa, optimize = einsum_type)
        sigma_KLWU -= einsum('Kx,xy,LyUW->KLWU', X, h_aa, t1_xaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Lx,Uy,KxWy->KLWU', X, h_aa, t1_xaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Lx,Wy,KxyU->KLWU', X, h_aa, t1_xaaa, optimize = einsum_type)
        sigma_KLWU -= einsum('Lx,xy,KyWU->KLWU', X, h_aa, t1_xaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Lxyz,UyWz->KLWU', X, t1_xaaa, v_aaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Ly,UyWx->KLWU', X, t1_xa, v_aaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Lx,Kxyz,UzWy->KLWU', X, t1_xaaa, v_aaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Lx,Ky,UxWy->KLWU', X, t1_xa, v_aaaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,LUxy,Wy->KLWU', X, v_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,LyxW,Uy->KLWU', X, v_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Kx,Lyxz,UWyz->KLWU', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/6 * einsum('Kx,Lyxz,UWzy->KLWU', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Lx,KWxy,Uy->KLWU', X, v_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Lx,KyxU,Wy->KLWU', X, v_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/6 * einsum('Lx,Kyxz,UWyz->KLWU', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Lx,Kyxz,UWzy->KLWU', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('iU,LiKx,Wx->KLWU', X, v_xxxa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('iW,KiLx,Ux->KLWU', X, v_xxxa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('ix,KiLU,Wx->KLWU', X, v_xxxa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/6 * einsum('ix,KiLy,UWxy->KLWU', X, v_xxxa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('ix,KiLy,UWyx->KLWU', X, v_xxxa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('ix,LiKW,Ux->KLWU', X, v_xxxa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('ix,LiKy,UWxy->KLWU', X, v_xxxa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/6 * einsum('ix,LiKy,UWyx->KLWU', X, v_xxxa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Kx,L,LxUy,Wy->KLWU', X, e_cvs, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Kx,L,LxyW,Uy->KLWU', X, e_cvs, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('Kx,L,Lxyz,UWyz->KLWU', X, e_cvs, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/6 * einsum('Kx,L,Lxyz,UWzy->KLWU', X, e_cvs, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Lx,K,KxWy,Uy->KLWU', X, e_cvs, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Lx,K,KxyU,Wy->KLWU', X, e_cvs, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/6 * einsum('Lx,K,Kxyz,UWyz->KLWU', X, e_cvs, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('Lx,K,Kxyz,UWzy->KLWU', X, e_cvs, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,Uy,Lxyz,Wz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,Wy,Lxzy,Uz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Kx,xy,LyUz,Wz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Kx,xy,LyzW,Uz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/6 * einsum('Kx,xy,Lyzw,UWwz->KLWU', X, h_aa, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('Kx,xy,Lyzw,UWzw->KLWU', X, h_aa, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,yz,LxUy,Wz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Kx,yz,Lxwy,UWwz->KLWU', X, h_aa, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/6 * einsum('Kx,yz,Lxwy,UWzw->KLWU', X, h_aa, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,yz,LxyW,Uz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/6 * einsum('Kx,yz,Lxyw,UWwz->KLWU', X, h_aa, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Kx,yz,Lxyw,UWzw->KLWU', X, h_aa, t1_xaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Lx,Uy,Kxzy,Wz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Lx,Wy,Kxyz,Uz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Lx,xy,KyWz,Uz->KLWU', X, h_aa, t1_xaaa, rdm_ca, optimize = einsum_type)
