    # CCAA <- CE 
    def compute_sigma_vector__H1__h1_h0__CCAA_CE(mr_adc, X, sigma):

        cput1 = (logger.process_clock(), logger.perf_counter())
 
        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Two-electron integrals
        v_xaea = mr_adc.v2e.xaea

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa

        sigma_KLWU  = einsum('Ka,LUaW->KLWU', X, v_xaea, optimize = einsum_type)
        sigma_KLWU += einsum('La,KWaU->KLWU', X, v_xaea, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Ka,LUax,Wx->KLWU', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Ka,LxaW,Ux->KLWU', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Ka,Lxay,UWxy->KLWU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/6 * einsum('Ka,Lxay,UWyx->KLWU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('La,KWax,Ux->KLWU', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('La,KxaU,Wx->KLWU', X, v_xaea, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/6 * einsum('La,Kxay,UWxy->KLWU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('La,Kxay,UWyx->KLWU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
        sigma[ccaa] += np.ascontiguousarray(sigma_KLWU).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h1-h0 CCAA-CE", *cput1)

    def compute_sigma_vector__H1__h1_h0__CVAA_CA(mr_adc, X, sigma):

        cput1 = (logger.process_clock(), logger.perf_counter())
 
        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_val = mr_adc.mo_energy.v

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa
        v_vaaa = mr_adc.v2e.vaaa
        v_xxva = mr_adc.v2e.xxva
        v_vxxa = mr_adc.v2e.vxxa

        ## Amplitudes
        t1_va = mr_adc.t1.va
        t1_vaaa = mr_adc.t1.vaaa
 
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa
        rdm_cccaaa = mr_adc.rdm.cccaaa

        sigma_KLWU  = einsum('Kx,LUxW->KLWU', X, v_vaaa, optimize = einsum_type)
        sigma_KLWU -= einsum('iU,LiKW->KLWU', X, v_vxxa, optimize = einsum_type)
        sigma_KLWU -= einsum('iW,KiLU->KLWU', X, v_xxva, optimize = einsum_type)
        sigma_KLWU -= einsum('Kx,L,LxUW->KLWU', X, e_val, t1_vaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Uy,LxyW->KLWU', X, h_aa, t1_vaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Wy,LxUy->KLWU', X, h_aa, t1_vaaa, optimize = einsum_type)
        sigma_KLWU -= einsum('Kx,xy,LyUW->KLWU', X, h_aa, t1_vaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Lxyz,UyWz->KLWU', X, t1_vaaa, v_aaaa, optimize = einsum_type)
        sigma_KLWU += einsum('Kx,Ly,UyWx->KLWU', X, t1_va, v_aaaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,LUxy,Wy->KLWU', X, v_vaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,LyxW,Uy->KLWU', X, v_vaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Kx,Lyxz,UWyz->KLWU', X, v_vaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/6 * einsum('Kx,Lyxz,UWzy->KLWU', X, v_vaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('iU,LiKx,Wx->KLWU', X, v_vxxa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('iW,KiLx,Ux->KLWU', X, v_xxva, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('ix,KiLU,Wx->KLWU', X, v_xxva, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/6 * einsum('ix,KiLy,UWxy->KLWU', X, v_xxva, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('ix,KiLy,UWyx->KLWU', X, v_xxva, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('ix,LiKW,Ux->KLWU', X, v_vxxa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('ix,LiKy,UWxy->KLWU', X, v_vxxa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/6 * einsum('ix,LiKy,UWyx->KLWU', X, v_vxxa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Kx,L,LxUy,Wy->KLWU', X, e_val, t1_vaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Kx,L,LxyW,Uy->KLWU', X, e_val, t1_vaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/3 * einsum('Kx,L,Lxyz,UWyz->KLWU', X, e_val, t1_vaaa, rdm_ccaa, optimize = einsum_type)
