        sigma_KLWU -= 1/2 * einsum('Kx,Lxyz,UyWw,zw->KLWU', X, t1_vaaa, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,Lxyz,Uywu,Wuzw->KLWU', X, t1_vaaa, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU -= 1/2 * einsum('Kx,Lxyz,Uywz,Ww->KLWU', X, t1_vaaa, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Kx,Lxyz,Wwuy,Uwuz->KLWU', X, t1_vaaa, v_aaaa, rdm_ccaa, optimize = einsum_type)
