        sigma_KLWU += 1/6 * einsum('Kx,Lxyz,ywzu,UWuw->KLWU', X, t1_vaaa, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('Kx,Lxyz,ywzu,UWwu->KLWU', X, t1_vaaa, v_aaaa, rdm_ccaa, optimize = einsum_type)
