        sigma_KLWU -= 1/2 * einsum('Kx,LyUz,xwzu,Wywu->KLWU', X, t1_vaaa, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLWU += 1/2 * einsum('Kx,LyUz,xywu,Wwzu->KLWU', X, t1_vaaa, v_aaaa, rdm_ccaa, optimize = einsum_type)
