    def compute_sigma_vector__H1__h1_h0__CVEA_CA(mr_adc, X, sigma):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_val = mr_adc.mo_energy.v
        e_extern = mr_adc.mo_energy.e

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa
        v_vaae = mr_adc.v2e.vaae
        v_veaa = mr_adc.v2e.veaa
        v_vxxe = mr_adc.v2e.vxxe
        v_xxve = mr_adc.v2e.xxve

        ## Amplitudes
        t1_vaae = mr_adc.t1.vaae
        t1_vaea = mr_adc.t1.vaea
 
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa

        sigma_KLCW_abab  = einsum('Kx,LWxC->KLCW', X, v_vaae, optimize = einsum_type)
        sigma_KLCW_abab -= einsum('iW,LiKC->KLCW', X, v_vxxe, optimize = einsum_type)
        sigma_KLCW_abab += einsum('Kx,C,LxWC->KLCW', X, e_extern, t1_vaae, optimize = einsum_type)
        sigma_KLCW_abab -= einsum('Kx,L,LxWC->KLCW', X, e_val, t1_vaae, optimize = einsum_type)
        sigma_KLCW_abab += einsum('Kx,Wy,LxyC->KLCW', X, h_aa, t1_vaae, optimize = einsum_type)
        sigma_KLCW_abab -= einsum('Kx,xy,LyWC->KLCW', X, h_aa, t1_vaae, optimize = einsum_type)
        sigma_KLCW_abab -= 1/2 * einsum('Kx,LyxC,Wy->KLCW', X, v_vaae, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab += 1/2 * einsum('ix,LiKC,Wx->KLCW', X, v_vxxe, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab -= 1/2 * einsum('Kx,C,LxyC,Wy->KLCW', X, e_extern, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab += 1/2 * einsum('Kx,L,LxyC,Wy->KLCW', X, e_val, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab += 1/2 * einsum('Kx,xy,LyzC,Wz->KLCW', X, h_aa, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab -= 1/2 * einsum('Kx,yz,LxyC,Wz->KLCW', X, h_aa, t1_vaae, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab += einsum('Kx,LxyC,Wyzw,zw->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab -= 1/2 * einsum('Kx,LxyC,Wzwy,wz->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab -= 1/2 * einsum('Kx,LxyC,yzwu,Wwzu->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_abab -= einsum('Kx,LyWC,xyzw,zw->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab += 1/2 * einsum('Kx,LyWC,xzwy,wz->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab += 1/2 * einsum('Kx,LyzC,Wwyx,zw->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab -= 1/2 * einsum('Kx,LyzC,Wzwx,yw->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab -= 1/6 * einsum('Kx,LyzC,xwuy,Wuwz->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_abab -= 1/3 * einsum('Kx,LyzC,xwuy,Wuzw->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_abab += 1/3 * einsum('Kx,LyzC,xwzu,Wyuw->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_abab += 1/6 * einsum('Kx,LyzC,xwzu,Wywu->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_abab += 1/2 * einsum('Kx,LyzC,xywu,Wwzu->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma[cvea__abab] += np.ascontiguousarray(sigma_KLCW_abab).reshape(-1)

        sigma_KLCW_baab =- einsum('Kx,LCxW->KLCW', X, v_veaa, optimize = einsum_type)
        sigma_KLCW_baab += einsum('iW,KiLC->KLCW', X, v_xxve, optimize = einsum_type)
        sigma_KLCW_baab -= einsum('Kx,C,LxCW->KLCW', X, e_extern, t1_vaea, optimize = einsum_type)
        sigma_KLCW_baab += einsum('Kx,L,LxCW->KLCW', X, e_val, t1_vaea, optimize = einsum_type)
        sigma_KLCW_baab -= einsum('Kx,Wy,LxCy->KLCW', X, h_aa, t1_vaea, optimize = einsum_type)
        sigma_KLCW_baab += einsum('Kx,xy,LyCW->KLCW', X, h_aa, t1_vaea, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,LCxy,Wy->KLCW', X, v_veaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('ix,KiLC,Wx->KLCW', X, v_xxve, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,C,LxCy,Wy->KLCW', X, e_extern, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('Kx,L,LxCy,Wy->KLCW', X, e_val, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('Kx,xy,LyCz,Wz->KLCW', X, h_aa, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,yz,LxCy,Wz->KLCW', X, h_aa, t1_vaea, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= einsum('Kx,LxCy,Wyzw,zw->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,LxCy,Wzwy,wz->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,LxCy,yzwu,Wwzu->KLCW', X, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_baab += einsum('Kx,LyCW,xyzw,zw->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('Kx,LyCW,xzwy,wz->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('Kx,LyCz,Wwyx,zw->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= einsum('Kx,LyCz,Wxwz,yw->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab += einsum('Kx,LyCz,Wxyw,zw->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,LyCz,Wzwx,yw->KLCW', X, t1_vaea, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('Kx,LyCz,xwuy,Wuwz->KLCW', X, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,LyCz,xwzu,Wywu->KLCW', X, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('Kx,LyCz,xywu,Wwzu->KLCW', X, t1_vaea, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Kx,LyzC,Wxwz,yw->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('Kx,LyzC,Wxyw,zw->KLCW', X, t1_vaae, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab += 1/3 * einsum('Kx,LyzC,xwuy,Wuwz->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_baab += 1/6 * einsum('Kx,LyzC,xwuy,Wuzw->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_baab -= 1/6 * einsum('Kx,LyzC,xwzu,Wyuw->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KLCW_baab -= 1/3 * einsum('Kx,LyzC,xwzu,Wywu->KLCW', X, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma[cvea__baab] += np.ascontiguousarray(sigma_KLCW_baab).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h1-h0 CVEA-CA", *cput1)

    def compute_sigma_vector__H1__h1_h0__CVEA_CE(mr_adc, X, sigma):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Two-electron integrals
        #v_veea = mr_adc.v2e.veea
        #v_vaee = mr_adc.v2e.vaee
        v_xxva = mr_adc.v2e.xxva
        v_vxxa = mr_adc.v2e.vxxa

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        #sigma_KLCW_abab  = einsum('Ka,LWaC->KLCW', X, v_vaee, optimize = einsum_type)
        sigma_KLCW_abab =- einsum('iC,KiLW->KLCW', X, v_xxva, optimize = einsum_type)
        #sigma_KLCW_abab -= 1/2 * einsum('Ka,LxaC,Wx->KLCW', X, v_vaee, rdm_ca, optimize = einsum_type)
        sigma_KLCW_abab += 1/2 * einsum('iC,KiLx,Wx->KLCW', X, v_xxva, rdm_ca, optimize = einsum_type)
        sigma[cvea__abab] += np.ascontiguousarray(sigma_KLCW_abab).reshape(-1)

        #sigma_KLCW_baab =- einsum('Ka,LCaW->KLCW', X, v_veea, optimize = einsum_type)
        sigma_KLCW_baab  = einsum('iC,LiKW->KLCW', X, v_vxxa, optimize = einsum_type)
        #sigma_KLCW_baab += 1/2 * einsum('Ka,LCax,Wx->KLCW', X, v_veea, rdm_ca, optimize = einsum_type)
        sigma_KLCW_baab -= 1/2 * einsum('iC,LiKx,Wx->KLCW', X, v_vxxa, rdm_ca, optimize = einsum_type)
        sigma[cvea__baab] += np.ascontiguousarray(sigma_KLCW_baab).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h1-h0 CVEA-CE", *cput1)

    def compute_sigma_vector__H1__h1_h0__CVEA_CE__V_VEEA(mr_adc, X, sigma, v_veea):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KLCW_baab =- einsum('Ka,LCaW->KLCW', X, v_veea, optimize = einsum_type)
        sigma_KLCW_baab += 1/2 * einsum('Ka,LCax,Wx->KLCW', X, v_veea, rdm_ca, optimize = einsum_type)
        sigma[cvea__baab] += np.ascontiguousarray(sigma_KLCW_baab).reshape(-1)

        mr_adc.log.timer_debug("contracting v2e.veea", *cput1)

    def compute_sigma_vector__H1__h1_h0__CVEA_CE__V_VAEE(mr_adc, X, sigma, v_vaee):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KLCW_abab  = einsum('Ka,LWaC->KLCW', X, v_vaee, optimize = einsum_type)
        sigma_KLCW_abab -= 1/2 * einsum('Ka,LxaC,Wx->KLCW', X, v_vaee, rdm_ca, optimize = einsum_type)
        sigma[cvea__abab] += np.ascontiguousarray(sigma_KLCW_abab).reshape(-1)

        mr_adc.log.timer_debug("contracting v2e.vaee", *cput1)

    def compute_sigma_vector__H1__h1_h0__CCEE_CA__V_XEAE(mr_adc, X, sigma, v_xeae):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        sigma_KLCD  = einsum('Kx,LDxC->KLCD', X, v_xeae, optimize = einsum_type)
        sigma_KLCD += einsum('Lx,KCxD->KLCD', X, v_xeae, optimize = einsum_type)
        sigma[ccee] += np.ascontiguousarray(sigma_KLCD).reshape(-1)

        mr_adc.log.timer_debug("contracting v2e.xeae", *cput1)

    def compute_sigma_vector__H1__h1_h0__CCEE_CA__T1_XAEE(mr_adc, X, sigma, t1_xaee_cd, t1_xaee_dc, e_extern_d):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_cvs = mr_adc.mo_energy.x
        e_extern = mr_adc.mo_energy.e

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KLCD  = einsum('Kx,C,LxDC->KLCD', X, e_extern, t1_xaee_dc, optimize = einsum_type)
        sigma_KLCD += einsum('Kx,D,LxDC->KLCD', X, e_extern_d, t1_xaee_dc, optimize = einsum_type)
        sigma_KLCD -= einsum('Kx,L,LxDC->KLCD', X, e_cvs, t1_xaee_dc, optimize = einsum_type)
        sigma_KLCD -= einsum('Kx,xy,LyDC->KLCD', X, h_aa, t1_xaee_dc, optimize = einsum_type)
        sigma_KLCD += einsum('Lx,C,KxCD->KLCD', X, e_extern, t1_xaee_cd, optimize = einsum_type)
        sigma_KLCD += einsum('Lx,D,KxCD->KLCD', X, e_extern_d, t1_xaee_cd, optimize = einsum_type)
        sigma_KLCD -= einsum('Lx,K,KxCD->KLCD', X, e_cvs, t1_xaee_cd, optimize = einsum_type)
        sigma_KLCD -= einsum('Lx,xy,KyCD->KLCD', X, h_aa, t1_xaee_cd, optimize = einsum_type)
        sigma_KLCD -= einsum('Kx,LyDC,xyzw,zw->KLCD', X, t1_xaee_dc, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCD += 1/2 * einsum('Kx,LyDC,xzwy,wz->KLCD', X, t1_xaee_dc, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCD -= einsum('Lx,KyCD,xyzw,zw->KLCD', X, t1_xaee_cd, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCD += 1/2 * einsum('Lx,KyCD,xzwy,wz->KLCD', X, t1_xaee_cd, v_aaaa, rdm_ca, optimize = einsum_type)
 
        mr_adc.log.timer_debug("contracting t1.xaee", *cput1)

        return sigma_KLCD

    def compute_sigma_vector__H1__h1_h0__CCEE_CE(mr_adc, X, sigma):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Two-electron integrals
        #v_xeee = mr_adc.v2e.xeee
        v_xxxe = mr_adc.v2e.xxxe

        #sigma_KLCD  = einsum('Ka,LDaC->KLCD', X, v_xeee, optimize = einsum_type)
        #sigma_KLCD += einsum('La,KCaD->KLCD', X, v_xeee, optimize = einsum_type)
        sigma_KLCD =- einsum('iC,KiLD->KLCD', X, v_xxxe, optimize = einsum_type)
        sigma_KLCD -= einsum('iD,LiKC->KLCD', X, v_xxxe, optimize = einsum_type)
        sigma[ccee] += np.ascontiguousarray(sigma_KLCD).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h1-h0 CCEE-CE", *cput1)

    def compute_sigma_vector__H1__h1_h0__CCEE_CE__V_XEEE(mr_adc, X, sigma, v_xeee):
 
        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        sigma_KLCD  = einsum('Ka,LDaC->KLCD', X, v_xeee, optimize = einsum_type)
        sigma_KLCD += einsum('La,KCaD->KLCD', X, v_xeee, optimize = einsum_type)
        sigma[ccee] += np.ascontiguousarray(sigma_KLCD).reshape(-1)

        mr_adc.log.timer_debug("contracting v2e.xeee", *cput1)

    def compute_sigma_vector__H1__h1_h0__CVEE_CA__V_VEAE(mr_adc, X, sigma, v_veae):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type
 
        sigma_KLCD  = einsum('Kx,LDxC->KLCD', X, v_veae, optimize = einsum_type)
        sigma[cvee] += np.ascontiguousarray(sigma_KLCD).reshape(-1)
            
    def compute_sigma_vector__H1__h1_h0__CVEE_CA__T1_VAEE(mr_adc, X, sigma, t1_vaee, e_extern_d):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_val = mr_adc.mo_energy.v
        e_extern = mr_adc.mo_energy.e

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa
 
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca

        sigma_KLCD  = einsum('Kx,C,LxDC->KLCD', X, e_extern, t1_vaee, optimize = einsum_type)
        sigma_KLCD += einsum('Kx,D,LxDC->KLCD', X, e_extern_d, t1_vaee, optimize = einsum_type)
        sigma_KLCD -= einsum('Kx,L,LxDC->KLCD', X, e_val, t1_vaee, optimize = einsum_type)
        sigma_KLCD -= einsum('Kx,xy,LyDC->KLCD', X, h_aa, t1_vaee, optimize = einsum_type)
        sigma_KLCD -= einsum('Kx,LyDC,xyzw,zw->KLCD', X, t1_vaee, v_aaaa, rdm_ca, optimize = einsum_type)
        sigma_KLCD += 1/2 * einsum('Kx,LyDC,xzwy,wz->KLCD', X, t1_vaee, v_aaaa, rdm_ca, optimize = einsum_type)

        mr_adc.log.timer_debug("contracting t1.vaee", *cput1)
        return sigma_KLCD

    def compute_sigma_vector__H1__h1_h0__CVEE_CE(mr_adc, X, sigma):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Two-electron integrals
        #v_veee = mr_adc.v2e.veee
        v_xxve = mr_adc.v2e.xxve
        v_vxxe = mr_adc.v2e.vxxe

        #sigma_KLCD  = einsum('Ka,LDaC->KLCD', X, v_veee, optimize = einsum_type)
        sigma_KLCD =- einsum('iC,KiLD->KLCD', X, v_xxve, optimize = einsum_type)
        sigma_KLCD -= einsum('iD,LiKC->KLCD', X, v_vxxe, optimize = einsum_type)
        sigma[cvee] += np.ascontiguousarray(sigma_KLCD).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H1 h1-h0 CVEE-CE", *cput1)

    def compute_sigma_vector__H1__h1_h0__CVEE_CE__V_VEEE(mr_adc, X, sigma, v_veee):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        sigma_KLCD  = einsum('Ka,LDaC->KLCD', X, v_veee, optimize = einsum_type)
        sigma[cvee] += np.ascontiguousarray(sigma_KLCD).reshape(-1)

        mr_adc.log.timer_debug("contracting v2e.veee", *cput1)

    def compute_sigma_vector__H1__h1_h0__CAEE_CA__V_AEAE(mr_adc, X, sigma, v_aeae):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
 
        sigma_KWCD  = 1/2 * einsum('Kx,xCyD,Wy->KWCD', X, v_aeae, rdm_ca, optimize = einsum_type)
        sigma[caee] += np.ascontiguousarray(sigma_KWCD).reshape(-1)

        mr_adc.log.timer_debug("contracting v2e.aeae", *cput1)

    def compute_sigma_vector__H1__h1_h0__CAEE_CA__T1_AAEE(mr_adc, X, sigma, t1_aaee, e_extern_d):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_extern = mr_adc.mo_energy.e

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa
 
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa

        sigma_KWCD  = 1/2 * einsum('Kx,C,xyCD,Wy->KWCD', X, e_extern, t1_aaee, rdm_ca, optimize = einsum_type)
        sigma_KWCD += 1/2 * einsum('Kx,D,xyCD,Wy->KWCD', X, e_extern_d, t1_aaee, rdm_ca, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('Kx,xy,yzCD,Wz->KWCD', X, h_aa, t1_aaee, rdm_ca, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('Kx,yz,xyCD,Wz->KWCD', X, h_aa, t1_aaee, rdm_ca, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('Kx,xyCD,yzwu,Wwzu->KWCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KWCD += 1/6 * einsum('Kx,yzCD,xwuy,Wwuz->KWCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KWCD += 1/3 * einsum('Kx,yzCD,xwuy,Wwzu->KWCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KWCD += 1/3 * einsum('Kx,yzCD,xwuz,Wwuy->KWCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KWCD += 1/6 * einsum('Kx,yzCD,xwuz,Wwyu->KWCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('Kx,yzCD,xywu,Wuzw->KWCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('Kx,yzCD,xywz,Ww->KWCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)

