        sigma_KLWU += 1/6 * einsum('KLxy,xzwu,UWwzyu->KLWU', X, v_aaaa, rdm_cccaaa, optimize = einsum_type)
        sigma_KLWU += 1/3 * einsum('KLxy,xzyw,UWwz->KLWU', X, v_aaaa, rdm_ccaa, optimize = einsum_type)
