        sigma_KLCW += 1/2 * einsum('KLCx,L,Wx->KLCW', X, e_cvs, rdm_ca, optimize = einsum_type)
        sigma_KLCW -= 1/2 * einsum('KLCx,xy,Wy->KLCW', X, h_aa, rdm_ca, optimize = einsum_type)
        sigma_KLCW -= 1/2 * einsum('KLCx,Wyzx,zy->KLCW', X, v_aaaa, rdm_ca, optimize = einsum_type)
