    # CAEE <- CAEE
    def compute_sigma_vector__H0__h1_h1__CAEE(mr_adc, X, sigma):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_cvs = mr_adc.mo_energy.x
        e_extern = mr_adc.mo_energy.e

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa

        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa
        
        sigma_KWCD  = 1/2 * einsum('KxCD,C,Wx->KWCD', X, e_extern, rdm_ca, optimize = einsum_type)
        sigma_KWCD += 1/2 * einsum('KxCD,D,Wx->KWCD', X, e_extern, rdm_ca, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('KxCD,K,Wx->KWCD', X, e_cvs, rdm_ca, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('KxCD,xy,Wy->KWCD', X, h_aa, rdm_ca, optimize = einsum_type)
        sigma_KWCD -= 1/2 * einsum('KxCD,xyzw,Wzyw->KWCD', X, v_aaaa, rdm_ccaa, optimize = einsum_type)
        sigma[caee] += np.ascontiguousarray(sigma_KWCD).reshape(-1)

        mr_adc.log.timer_debug("computing sigma H0 h1 CAEE", *cput1)

    # CAAA <- CAAA
    def compute_sigma_vector__H0__h1_h1__CAAA(mr_adc, X_aaaa, X_abab, sigma, ints):

        cput1 = (logger.process_clock(), logger.perf_counter())

        # Einsum definition from kernel
        einsum = mr_adc.interface.einsum
        einsum_type = mr_adc.interface.einsum_type

        ## Molecular Orbitals Energies
        e_cvs = mr_adc.mo_energy.x

        ## One-electron integrals
        h_aa = mr_adc.h1eff.aa

        ## Two-electron integrals
        v_aaaa = mr_adc.v2e.aaaa
 
        # Reduced Density Matrices
        rdm_ca = mr_adc.rdm.ca
        rdm_ccaa = mr_adc.rdm.ccaa
        rdm_cccaaa = mr_adc.rdm.cccaaa

        # Intermediates
        INT01, INT02, INT03, INT04, INT05, INT06, INT07, INT08 = ints

        sigma_KWUV_aaaa =- 1/2 * einsum('KxUV,K,Wx->KWUV', X_aaaa, e_cvs, rdm_ca, optimize = einsum_type)
        sigma_KWUV_aaaa -= 1/6 * einsum('KxUy,K,VxWy->KWUV', X_aaaa, e_cvs, rdm_ccaa, optimize = einsum_type)
        sigma_KWUV_aaaa += 1/6 * einsum('KxUy,K,VxyW->KWUV', X_aaaa, e_cvs, rdm_ccaa, optimize = einsum_type)
        sigma_KWUV_aaaa += 1/6 * einsum('KxVy,K,UxWy->KWUV', X_aaaa, e_cvs, rdm_ccaa, optimize = einsum_type)
        sigma_KWUV_aaaa -= 1/6 * einsum('KxVy,K,UxyW->KWUV', X_aaaa, e_cvs, rdm_ccaa, optimize = einsum_type)
        sigma_KWUV_aaaa += 1/24 * einsum('Kxyz,K,UVxWzy->KWUV', X_aaaa, e_cvs, rdm_cccaaa, optimize = einsum_type)
        sigma_KWUV_aaaa -= 1/24 * einsum('Kxyz,K,UVxzWy->KWUV', X_aaaa, e_cvs, rdm_cccaaa, optimize = einsum_type)
        sigma_KWUV_aaaa += 1/24 * einsum('Kxyz,K,UVxzyW->KWUV', X_aaaa, e_cvs, rdm_cccaaa, optimize = einsum_type)
        sigma_KWUV_aaaa -= 1/2 * einsum('KxUV,xy,Wy->KWUV', X_aaaa, h_aa, rdm_ca, optimize = einsum_type)
        sigma_KWUV_aaaa += 1/2 * einsum('KxUy,Vy,Wx->KWUV', X_aaaa, h_aa, rdm_ca, optimize = einsum_type)
        sigma_KWUV_aaaa -= 1/6 * einsum('KxUy,xz,VzWy->KWUV', X_aaaa, h_aa, rdm_ccaa, optimize = einsum_type)
        sigma_KWUV_aaaa += 1/6 * einsum('KxUy,xz,VzyW->KWUV', X_aaaa, h_aa, rdm_ccaa, optimize = einsum_type)
        sigma_KWUV_aaaa += 1/6 * einsum('KxUy,yz,VxWz->KWUV', X_aaaa, h_aa, rdm_ccaa, optimize = einsum_type)
