        temp -= einsum('RijPx,jiyQ,xy->RPQ', Y_KLWU, t1_xxae, rdm_ca, optimize = einsum_type)
        temp -= einsum('Rijxy,ijxQ,Py->RPQ', Y_KLWU, t1_xxae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('Rijxy,jixQ,Py->RPQ', Y_KLWU, t1_xxae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('Rijxy,jizQ,Pzxy->RPQ', Y_KLWU, t1_xxae, rdm_ccaa, optimize = einsum_type)
        TY[:, s_a:f_a, s_e:f_e] += temp

        mr_adc.log.timer_debug("computing T q1-h1 CCAA", *cput1)

