        temp += einsum('Rijax,ijPa,Qx->RPQ', Y_KLCW__baab, t1_xvae, rdm_ca, optimize = einsum_type)
        temp -= 1/2 * einsum('Rijax,jiPa,Qx->RPQ', Y_KLCW__baab, t1_vxae, rdm_ca, optimize = einsum_type)
