        temp =- einsum('RijQx,ijxP->RPQ', Y_KLCW__abab, t1_xvae, optimize = einsum_type)
        temp += 2 * einsum('RijQx,jixP->RPQ', Y_KLCW__abab, t1_vxae, optimize = einsum_type)
        temp -= 2 * einsum('RijQx,ijxP->RPQ', Y_KLCW__baab, t1_xvae, optimize = einsum_type)
        temp += einsum('RijQx,jixP->RPQ', Y_KLCW__baab, t1_vxae, optimize = einsum_type)
        temp += 1/2 * einsum('RijQx,ijyP,xy->RPQ', Y_KLCW__abab, t1_xvae, rdm_ca, optimize = einsum_type)
        temp -= einsum('RijQx,jiyP,xy->RPQ', Y_KLCW__abab, t1_vxae, rdm_ca, optimize = einsum_type)
        temp += einsum('RijQx,ijyP,xy->RPQ', Y_KLCW__baab, t1_xvae, rdm_ca, optimize = einsum_type)
        temp -= 1/2 * einsum('RijQx,jiyP,xy->RPQ', Y_KLCW__baab, t1_vxae, rdm_ca, optimize = einsum_type)
        TY[:, s_e:f_e, s_e:f_e] += temp

        temp = einsum('RPiax,Qixa->RPQ', Y_KLCW__abab, t1_vvae, optimize = einsum_type)
        temp -= 2 * einsum('RPiax,iQxa->RPQ', Y_KLCW__abab, t1_vvae, optimize = einsum_type)
        temp -= 2 * einsum('RiQax,Pixa->RPQ', Y_KLCW__abab, t1_xxae, optimize = einsum_type)
        temp += einsum('RiQax,iPxa->RPQ', Y_KLCW__abab, t1_xxae, optimize = einsum_type)
        temp += 2 * einsum('RPiax,Qixa->RPQ', Y_KLCW__baab, t1_vvae, optimize = einsum_type)
        temp -= einsum('RPiax,iQxa->RPQ', Y_KLCW__baab, t1_vvae, optimize = einsum_type)
        temp -= einsum('RiQax,Pixa->RPQ', Y_KLCW__baab, t1_xxae, optimize = einsum_type)
        temp += 2 * einsum('RiQax,iPxa->RPQ', Y_KLCW__baab, t1_xxae, optimize = einsum_type)
        temp -= 1/2 * einsum('RPiax,Qiya,xy->RPQ', Y_KLCW__abab, t1_vvae, rdm_ca, optimize = einsum_type)
        temp += einsum('RPiax,iQya,xy->RPQ', Y_KLCW__abab, t1_vvae, rdm_ca, optimize = einsum_type)
        temp += einsum('RiQax,Piya,xy->RPQ', Y_KLCW__abab, t1_xxae, rdm_ca, optimize = einsum_type)
        temp -= 1/2 * einsum('RiQax,iPya,xy->RPQ', Y_KLCW__abab, t1_xxae, rdm_ca, optimize = einsum_type)
        temp -= einsum('RPiax,Qiya,xy->RPQ', Y_KLCW__baab, t1_vvae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('RPiax,iQya,xy->RPQ', Y_KLCW__baab, t1_vvae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('RiQax,Piya,xy->RPQ', Y_KLCW__baab, t1_xxae, rdm_ca, optimize = einsum_type)
        temp -= einsum('RiQax,iPya,xy->RPQ', Y_KLCW__baab, t1_xxae, rdm_ca, optimize = einsum_type)
        TY[:, s_c:f_c, s_v:f_v] += temp

