        temp -= 2 * einsum('RPiax,iQxa->RPQ', Y_KLCW__abab, t1_vaae, optimize = einsum_type)
        temp += 2 * einsum('RPiax,iQax->RPQ', Y_KLCW__baab, t1_vaea, optimize = einsum_type)
        temp -= einsum('RPiax,iQxa->RPQ', Y_KLCW__baab, t1_vaae, optimize = einsum_type)
        temp -= 1/2 * einsum('RPiax,iQay,xy->RPQ', Y_KLCW__abab, t1_vaea, rdm_ca, optimize = einsum_type)
        temp += einsum('RPiax,iQya,xy->RPQ', Y_KLCW__abab, t1_vaae, rdm_ca, optimize = einsum_type)
        temp -= einsum('RPiax,iQay,xy->RPQ', Y_KLCW__baab, t1_vaea, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('RPiax,iQya,xy->RPQ', Y_KLCW__baab, t1_vaae, rdm_ca, optimize = einsum_type)
        TY[:, s_c:f_c, s_a:f_a] += temp

        temp =- 2 * einsum('RiPax,iQax->RPQ', Y_KLCW__abab, t1_xaea, optimize = einsum_type)
        temp += einsum('RiPax,iQxa->RPQ', Y_KLCW__abab, t1_xaae, optimize = einsum_type)
        temp -= einsum('RiPax,iQax->RPQ', Y_KLCW__baab, t1_xaea, optimize = einsum_type)
        temp += 2 * einsum('RiPax,iQxa->RPQ', Y_KLCW__baab, t1_xaae, optimize = einsum_type)
        temp += einsum('RiPax,iQay,xy->RPQ', Y_KLCW__abab, t1_xaea, rdm_ca, optimize = einsum_type)
        temp -= 1/2 * einsum('RiPax,iQya,xy->RPQ', Y_KLCW__abab, t1_xaae, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('RiPax,iQay,xy->RPQ', Y_KLCW__baab, t1_xaea, rdm_ca, optimize = einsum_type)
        temp -= einsum('RiPax,iQya,xy->RPQ', Y_KLCW__baab, t1_xaae, rdm_ca, optimize = einsum_type)
        TY[:, s_v:f_v, s_a:f_a] += temp

        temp = 2 * einsum('RijQx,ijPx->RPQ', Y_KLCW__abab, t1_xvaa, optimize = einsum_type)
        temp -= einsum('RijQx,jiPx->RPQ', Y_KLCW__abab, t1_vxaa, optimize = einsum_type)
        temp -= einsum('RijaP,ijQa->RPQ', Y_KLCW__abab, t1_xvee, optimize = einsum_type)
        temp += 2 * einsum('RijaP,jiQa->RPQ', Y_KLCW__abab, t1_vxee, optimize = einsum_type)
        temp += einsum('RijQx,ijPx->RPQ', Y_KLCW__baab, t1_xvaa, optimize = einsum_type)
        temp -= 2 * einsum('RijQx,jiPx->RPQ', Y_KLCW__baab, t1_vxaa, optimize = einsum_type)
        temp -= 2 * einsum('RijaP,ijQa->RPQ', Y_KLCW__baab, t1_xvee, optimize = einsum_type)
        temp += einsum('RijaP,jiQa->RPQ', Y_KLCW__baab, t1_vxee, optimize = einsum_type)
        temp -= einsum('RijQx,ijPy,xy->RPQ', Y_KLCW__abab, t1_xvaa, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('RijQx,jiPy,xy->RPQ', Y_KLCW__abab, t1_vxaa, rdm_ca, optimize = einsum_type)
        temp += 1/2 * einsum('Rijax,ijQa,Px->RPQ', Y_KLCW__abab, t1_xvee, rdm_ca, optimize = einsum_type)
        temp -= einsum('Rijax,jiQa,Px->RPQ', Y_KLCW__abab, t1_vxee, rdm_ca, optimize = einsum_type)
        temp -= 1/2 * einsum('RijQx,ijPy,xy->RPQ', Y_KLCW__baab, t1_xvaa, rdm_ca, optimize = einsum_type)
        temp += einsum('RijQx,jiPy,xy->RPQ', Y_KLCW__baab, t1_vxaa, rdm_ca, optimize = einsum_type)
        temp += einsum('Rijax,ijQa,Px->RPQ', Y_KLCW__baab, t1_xvee, rdm_ca, optimize = einsum_type)
